import { serve } from "https://deno.land/std@0.168.0/http/server.ts";
import { createClient } from "https://esm.sh/@supabase/supabase-js@2";
import { getOwner, isOwnerPhoneInList, parseOwnerPhonesList, normalizePhone } from "../_shared/getOwner.ts";
import { runAssistente, runAtendente } from "../_shared/agentLogic.ts";
import type { PromptIntent, PromptStage } from "../_shared/atendentePromptModules.ts";
import type { Intent as SmartIntent } from "../_shared/routeNotes.ts";
import { sendTicketFlowOrder } from "../_shared/ticketflow.ts";
import {
  sanitizeMessage,
  sanitizePhone,
  sanitizeName,
  isAllowedEvolutionBaseUrl,
  verifyWebhookSecret,
} from "../_shared/security.ts";
import {
  extractTextFromPdf,
  isPdfMimetype,
  isPdfFileName,
} from "../_shared/pdfExtract.ts";

const corsHeaders = {
  "Access-Control-Allow-Origin": "*",
  "Access-Control-Allow-Headers": "authorization, x-client-info, apikey, content-type, x-webhook-secret",
};

const EVOLUTION_KEYS = ["evolution_base_url", "evolution_api_key", "evolution_instance", "evolution_webhook_secret"] as const;
const SEND_MESSAGE_TIMEOUT_MS = 12000;
const CARDAPIO_PDF_URL = "http://bit.ly/3OYW9Fw";
const DEBOUNCE_MS = 4000; // Espera 4 segundos para agrupar mensagens rápidas

function getEvolutionConfig(settings: { key: string; value: string }[]) {
  const map = new Map(settings.map((s) => [s.key, s.value]));
  const baseUrl = (map.get("evolution_base_url") || "").trim().replace(/\/$/, "");
  const apiKey = (map.get("evolution_api_key") || "").trim();
  let instance = (map.get("evolution_instance") || "default").trim() || "default";
  instance = instance.replace(/\s+/g, "-");
  const webhookSecret = (map.get("evolution_webhook_secret") || "").trim() || null;
  return { baseUrl, apiKey, instance, webhookSecret };
}

function extractMessageText(payload: Record<string, unknown>): string {
  const msg = payload.message as Record<string, unknown> | undefined;
  if (!msg) return "";
  if (typeof msg.conversation === "string") return msg.conversation;
  const ext = msg.extendedTextMessage as { text?: string } | undefined;
  if (ext && typeof ext.text === "string") return ext.text;
  const doc = msg.documentMessage as { caption?: string } | undefined;
  if (doc && typeof doc.caption === "string") return doc.caption;
  return "";
}

/** Verifica se o payload tem um documento PDF (documentMessage com mimetype ou nome .pdf). */
function hasPdfDocument(payload: Record<string, unknown>): boolean {
  const msg = payload.message as Record<string, unknown> | undefined;
  if (!msg?.documentMessage) return false;
  const doc = msg.documentMessage as { mimetype?: string; fileName?: string };
  return isPdfMimetype(doc.mimetype) || isPdfFileName(doc.fileName);
}

/** Obtém os bytes do documento do payload: base64 embutido ou via Evolution getBase64FromMediaMessage. */
async function getDocumentBytes(
  payload: Record<string, unknown>,
  evo: { baseUrl: string; apiKey: string; instance: string }
): Promise<Uint8Array | null> {
  const msg = payload.message as Record<string, unknown> | undefined;
  const doc = msg?.documentMessage as { base64?: string } | undefined;
  if (doc?.base64 && typeof doc.base64 === "string") {
    try {
      const bin = Uint8Array.from(atob(doc.base64), (c) => c.charCodeAt(0));
      return bin.length > 0 && bin.length <= 5 * 1024 * 1024 ? bin : null;
    } catch {
      return null;
    }
  }
  if (!evo.baseUrl || !evo.apiKey || !isAllowedEvolutionBaseUrl(evo.baseUrl)) return null;
  try {
    const url = `${evo.baseUrl.replace(/\/$/, "")}/chat/getBase64FromMediaMessage/${encodeURIComponent(evo.instance)}`;
    const res = await fetch(url, {
      method: "POST",
      headers: { "Content-Type": "application/json", "apikey": evo.apiKey },
      body: JSON.stringify({ message: msg, key: payload.key }),
    });
    if (!res.ok) return null;
    const json = (await res.json().catch(() => null)) as { base64?: string } | null;
    const b64 = json?.base64;
    if (typeof b64 !== "string") return null;
    const bin = Uint8Array.from(atob(b64), (c) => c.charCodeAt(0));
    return bin.length > 0 && bin.length <= 5 * 1024 * 1024 ? bin : null;
  } catch {
    return null;
  }
}

function extractRemoteJid(payload: Record<string, unknown>): string {
  const key = payload.key as { remoteJid?: string } | undefined;
  const jid = key?.remoteJid || "";
  return String(jid).replace(/@.*$/, "").trim();
}

function extractMessageId(payload: Record<string, unknown>): string | null {
  const key = payload.key as { id?: string } | undefined;
  const id = key?.id;
  return typeof id === "string" && id.length > 0 && id.length <= 128 ? id : null;
}

function normalizeForCompare(text: string): string {
  return (text || "")
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/\s+/g, " ")
    .trim();
}

function buildRecentHistoryHint(history: { role: "user" | "assistant"; content: string }[]): string {
  const recent = history.slice(-6);
  if (recent.length === 0) return "";
  const lines = recent.map((h) => `${h.role === "user" ? "cliente" : "atendente"}: ${h.content.slice(0, 180)}`);
  return lines.join("\n");
}

function extractOrderMemory(history: { role: "user" | "assistant"; content: string }[]): {
  hasCake: boolean;
  hasSalgados: boolean;
  items: string[];
} {
  const text = history.map((h) => h.content || "").join("\n");
  const items: string[] = [];

  // Bolos com kg
  const cakeMatches = text.match(/bolo[^\n]*\d+\s*kg[^\n]*/gi) || [];
  // Bolos por sabor (ex: "Bolo Ninho com Morango de 4kg")
  const cakeNameMatches = text.match(/bolo\s+(?:de\s+)?[a-záàâãéèêíïóôõúüç\s]+(?:\d+\s*kg)?/gi) || [];
  // Mini salgados
  const miniMatches = text.match(/\d+\s*mini[^\n]*/gi) || [];
  // Salgados por nome (25 coxinhas, 25 quibes, etc.)
  const salgadoMatches = text.match(/\d+\s*(?:mini\s+)?(?:coxinha|quibe|bolinha|risole|empada|esfiha|enrolado|kibe)[^\n]*/gi) || [];
  // Quantidades genéricas com "salgados"
  const salgadoGenMatches = text.match(/\d+\s*(?:mini\s+)?salgados?[^\n]*/gi) || [];
  // Açaí
  const acaiMatches = text.match(/acai[^\n]*/gi) || text.match(/açaí[^\n]*/gi) || [];
  // Docinhos
  const docinhoMatches = text.match(/\d+\s*(?:brigadeiro|beijinho|cajuzinho|docinho)[^\n]*/gi) || [];
  // Fatias
  const fatiaMatches = text.match(/\d+\s*fatia[^\n]*/gi) || [];
  // Preços mencionados pelo atendente (ex: "R$548", "Total: R$723")
  const totalMatches = text.match(/total[:\s]*r\$\s*[\d.,]+/gi) || [];

  const allMatches = [
    ...cakeMatches, ...cakeNameMatches, ...miniMatches, ...salgadoMatches,
    ...salgadoGenMatches, ...acaiMatches, ...docinhoMatches, ...fatiaMatches, ...totalMatches
  ];

  for (const m of allMatches) {
    const cleaned = m.replace(/\s+/g, " ").trim().slice(0, 200);
    if (cleaned.length >= 5) items.push(cleaned);
  }
  const dedup = [...new Set(items)];
  const norm = dedup.map(i => normalizeForCompare(i));
  const hasCake = norm.some(i => i.includes("bolo"));
  const hasSalgados = norm.some(i => i.includes("salgado") || i.includes("mini") || i.includes("coxinha") || i.includes("quibe") || i.includes("risole"));
  return { hasCake, hasSalgados, items: dedup.slice(-12) };
}

function buildOrderMemoryHint(
  history: { role: "user" | "assistant"; content: string }[],
  sessionMemory?: Record<string, unknown>
): string {
  const mem = extractOrderMemory(history);

  // ── Extrair TODOS os detalhes já fornecidos pelo cliente ──
  const clientText = history.filter((h) => h.role === "user").map((h) => h.content || "").join("\n");

  // Pesos mencionados (regex do histórico)
  const allWeights = [...clientText.matchAll(/(\d+)\s*kg/gi)].map((m) => `${m[1]}kg`);
  const regexWeight = allWeights.length > 0 ? allWeights[allWeights.length - 1] : "";
  // Fallback: peso persistido na sessão (sobrevive entre invocações)
  const confirmedWeight = regexWeight || (sessionMemory?.confirmed_weight as string) || "";

  // Sabores de bolo mencionados pelo cliente
  const flavorMatches = [...clientText.matchAll(/(?:bolo\s+(?:de\s+)?|pode\s+ser\s+(?:de\s+)?|vai\s+ser\s+(?:de\s+)?|quero\s+(?:de\s+)?|o\s+de\s+)([a-záàâãéèêíïóôõúüç\s]+)/gi)];
  const flavors = flavorMatches.map((m) => m[1].trim()).filter((f) => f.length > 2 && !f.match(/^\d/));
  const regexFlavor = flavors.length > 0 ? flavors[flavors.length - 1] : "";
  // Fallback: sabor persistido na sessão
  const confirmedFlavor = regexFlavor || (sessionMemory?.confirmed_flavor as string) || "";

  // Quantidade de salgados
  const salgadoQty = [...clientText.matchAll(/(\d+)\s*(?:mini|salgado|coxinha|quibe)/gi)].map((m) => m[1]);
  const confirmedSalgadoQty = salgadoQty.length > 0 ? salgadoQty[salgadoQty.length - 1] : "";

  // Tipo de pedido (regex + fallback sessão)
  const regexOrderType = clientText.toLowerCase().includes("delivery") ? "delivery"
    : clientText.toLowerCase().includes("encomenda") ? "encomenda"
    : clientText.toLowerCase().includes("retirada") ? "retirada"
    : "";
  const orderType = regexOrderType || (sessionMemory?.order_type as string) || "";

  // Itens persistidos da sessão como fallback se o regex do histórico não pegou
  const sessionItems = (sessionMemory?.order_items as string[]) || [];
  const allItems = mem.items.length > 0 ? mem.items : sessionItems;

  // Se não tem nada, retornar vazio
  if (allItems.length === 0 && !confirmedWeight && !confirmedFlavor && !confirmedSalgadoQty && !orderType) {
    return "";
  }

  // Perguntas que o atendente fez e que estão PENDENTES de resposta
  const lastAssistantMsg = [...history].reverse().find((h) => h.role === "assistant");
  const pendingQuestions: string[] = [];
  if (lastAssistantMsg?.content?.includes("?")) {
    const questions = lastAssistantMsg.content.match(/[^.!]*\?/g) || [];
    pendingQuestions.push(...questions.map((q) => q.trim()));
  }

  // ── Montar resumo estruturado ──
  const details: string[] = [];
  if (confirmedWeight) details.push(`PESO: ${confirmedWeight} (já informado — NÃO pergunte de novo)`);
  if (confirmedFlavor) details.push(`SABOR: ${confirmedFlavor} (já informado — NÃO pergunte de novo)`);
  if (confirmedSalgadoQty) details.push(`SALGADOS: ${confirmedSalgadoQty} unidades (já informado — NÃO pergunte de novo)`);
  if (orderType) details.push(`TIPO: ${orderType} (já informado — NÃO pergunte de novo)`);

  return `[MEMORIA_DO_PEDIDO_EM_ANDAMENTO]
${allItems.length > 0 ? `Itens já citados/confirmados na conversa:\n${allItems.map((i) => `- ${i}`).join("\n")}` : ""}

DETALHES JÁ CONFIRMADOS PELO CLIENTE (usar sem re-perguntar):
${details.length > 0 ? details.map((d) => `✓ ${d}`).join("\n") : "(nenhum detalhe específico extraído)"}
${pendingQuestions.length > 0 ? `\nPERGUNTAS PENDENTES (última resposta do atendente):\n${pendingQuestions.map((q) => `? ${q}`).join("\n")}` : ""}

REGRA DE OURO: Antes de fazer QUALQUER pergunta, verifique se a resposta já está nos detalhes acima. Se estiver, USE a informação e NÃO pergunte.
[/MEMORIA_DO_PEDIDO_EM_ANDAMENTO]`;
}

function enforceCakeContinuity(
  replyText: string,
  fullMessage: string,
  history: { role: "user" | "assistant"; content: string }[]
): string {
  const msg = normalizeForCompare(fullMessage);

  // Detectar se o cliente está perguntando sobre item do pedido
  const asksCakeFollowup =
    msg.includes("meu bolo") || msg.includes("e o bolo") || msg.includes("e meu bolo") ||
    msg.includes("cade o bolo") || msg.includes("cadê o bolo") || msg.includes("esqueceu o bolo") ||
    msg.includes("e o pedido") || msg.includes("meu pedido");
  const asksSalgadoFollowup =
    msg.includes("meus salgados") || msg.includes("e os salgados") || msg.includes("e meus salgados");

  if (!asksCakeFollowup && !asksSalgadoFollowup) return replyText;

  const mem = extractOrderMemory(history);
  if (mem.items.length === 0) return replyText;

  const rep = normalizeForCompare(replyText);

  // Se perguntou do bolo e a resposta já menciona bolo, ok
  if (asksCakeFollowup && rep.includes("bolo") && mem.hasCake) return replyText;
  // Se perguntou de salgados e a resposta já menciona, ok
  if (asksSalgadoFollowup && (rep.includes("salgado") || rep.includes("mini")) && mem.hasSalgados) return replyText;

  // Montar resumo com todos os itens do pedido
  const itemsList = mem.items
    .filter(i => {
      const n = normalizeForCompare(i);
      return n.includes("bolo") || n.includes("mini") || n.includes("salgado") || n.includes("coxinha") || n.includes("quibe");
    })
    .map(i => `• ${i}`)
    .join("\n");

  if (!itemsList) return replyText;

  return `Não esqueci! 😊 Seu pedido até agora:\n${itemsList}\n\nQuer confirmar tudo ou mudar alguma coisa?`;
}

function buildPreviousQuestionHint(
  history: { role: "user" | "assistant"; content: string }[],
  currentMessage: string
): string {
  const msg = (currentMessage || "").trim();
  if (!msg || msg.length > 120) return "";

  // Buscar nas últimas 4 mensagens do atendente por perguntas não respondidas
  // Isso resolve o problema de perguntas que ficam "enterradas" por trocas intermediárias
  const assistantMsgs = history
    .map((h, idx) => ({ ...h, idx }))
    .filter((h) => h.role === "assistant" && !!h.content?.trim() && h.content.includes("?"));

  if (assistantMsgs.length === 0) return "";

  // Pegar as últimas 4 mensagens do atendente com perguntas
  const recentQuestions = assistantMsgs.slice(-4);
  const hints: string[] = [];

  for (const q of recentQuestions) {
    // Verificar se a pergunta já foi respondida por uma mensagem subsequente do cliente
    const subsequentUserMsgs = history
      .slice(q.idx + 1)
      .filter((h) => h.role === "user");

    const questionNorm = normalizeForCompare(q.content);

    // Se a pergunta era sobre sabor/peso/tipo e não foi respondida diretamente
    const asksFlavor = questionNorm.includes("sabor") || questionNorm.includes("qual sabor");
    const asksWeight = questionNorm.includes("peso") || questionNorm.includes("quantos kg") || questionNorm.includes("qual peso");
    const asksOrderType = questionNorm.includes("encomenda") && questionNorm.includes("delivery") && questionNorm.includes("retirada");

    // Se perguntou sabor e nenhuma resposta subsequente mencionou sabor, a pergunta segue pendente
    const wasAnswered = subsequentUserMsgs.some((u) => {
      const uNorm = normalizeForCompare(u.content);
      if (asksFlavor) {
        // Resposta de sabor precisa conter padrão de sabor real, não qualquer texto curto
        return uNorm.includes("sabor") ||
          /bolo\s+de\s+\w/.test(uNorm) ||
          /(?:pode\s+ser|vai\s+ser|quero|o\s+de|de)\s+[a-záàâãéèêíïóôõúüç]{3,}/i.test(uNorm) ||
          // Nomes de sabores comuns como resposta direta
          /(?:chocolate|morango|ninho|brigadeiro|mousse|maracuja|limao|coco|cenoura|red\s*velvet|prestígio|prestigio|abacaxi|doce\s+de\s+leite)/i.test(uNorm);
      }
      if (asksWeight) return /\d+\s*kg/.test(uNorm);
      if (asksOrderType) return uNorm.includes("delivery") || uNorm.includes("encomenda") || uNorm.includes("retirada");
      return false;
    });

    if (!wasAnswered || q === recentQuestions[recentQuestions.length - 1]) {
      hints.push(q.content.slice(0, 220));
    }
  }

  if (hints.length === 0) return "";

  // A pergunta mais relevante é a última com "?"
  const mostRelevant = hints[hints.length - 1];
  let hint = `A mensagem atual ("${msg}") parece resposta de uma pergunta anterior do atendente.\nPergunta anterior: ${mostRelevant}\nResposta atual do cliente: ${msg}`;

  // Se há mais perguntas pendentes, incluir contexto extra
  if (hints.length > 1) {
    hint += `\nOutras perguntas recentes do atendente (podem ter contexto relevante):\n${hints.slice(0, -1).map((h) => `- ${h.slice(0, 150)}`).join("\n")}`;
  }

  return hint;
}

// Reusar tipos do módulo de prompts para garantir consistência
type ConversationIntent = PromptIntent;
type ConversationStage = PromptStage;

function detectIntent(fullMessage: string): ConversationIntent {
  const msg = normalizeForCompare(fullMessage);

  // ── Saudações puras (só saudação, sem pedido ou pergunta) ──
  if (/^(oi+|ola|bom dia|boa tarde|boa noite|hey|eai|e ai|fala|opa|salve)\s*[!.,?😊🙂👋]*\s*$/i.test(msg)) return "greeting";
  // Saudação com "tudo bem?" no máximo
  if (/^(oi+|ola|bom dia|boa tarde|boa noite)\s*(tudo\s*(bem|bom|certo|joia))?\s*[!.,?😊]*\s*$/i.test(msg)) return "greeting";

  // ── Comprovante / confirmação de pagamento ──
  if (msg.includes("comprovante") || msg.includes("paguei") || msg.includes("ja paguei") ||
      msg.includes("fiz o pix") || msg.includes("transferi") || msg.includes("depositei") ||
      msg.includes("fiz a transferencia") || msg.includes("enviei o pix") ||
      msg.includes("ta pago") || msg.includes("tá pago") || msg.includes("pagamento feito")) return "payment_proof";
  // "pago" sozinho é ambíguo (pode ser "já está pago?") — só conta se combinado com ação
  if (msg.includes("pago") && (msg.includes("ja") || msg.includes("já") || msg.includes("ta") || msg.includes("tá") || msg.includes("tudo"))) return "payment_proof";
  // "pix" com ação de envio
  if (msg.includes("pix") && (msg.includes("fiz") || msg.includes("enviei") || msg.includes("mandei") || msg.includes("pronto") || msg.includes("feito"))) return "payment_proof";
  // Mensagem curta de confirmação — SÓ payment_proof se contexto tiver PIX/pagamento
  // (caso contrário, pode ser confirmação de sabor, peso, etc.)
  // Nota: essa detecção é refinada adiante no webhook com base no histórico

  // ── Cancelamento / mudança de ideia ──
  if (msg.includes("cancela") || msg.includes("desisti") || msg.includes("desistir") ||
      msg.includes("nao quero mais") || msg.includes("não quero mais") || msg.includes("esquece") ||
      msg.includes("deixa pra la") || msg.includes("deixa pra lá") || msg.includes("recomecar") ||
      msg.includes("recomeçar") || msg.includes("começar de novo") || msg.includes("comecar de novo")) return "other"; // mapped to "cancel" via smartIntentOverride in stage

  // ── Urgência de delivery ──
  if ((msg.includes("entregar") || msg.includes("delivery") || msg.includes("entrega")) &&
      (msg.includes("agora") || msg.includes("hoje") || msg.includes("urgente") || msg.includes("rapido") || msg.includes("ja"))) return "delivery_urgency";
  // "pra agora", "pra hoje"
  if ((msg.includes("pra agora") || msg.includes("para agora") || msg.includes("pra hoje") || msg.includes("para hoje")) &&
      (msg.includes("pedido") || msg.includes("pedir") || msg.includes("encomenda"))) return "delivery_urgency";

  // ── Início de pedido (antes de preço) ──
  if (msg.includes("quero pedir") || msg.includes("fazer um pedido") || msg.includes("gostaria de pedir") ||
      msg.includes("fazer pedido") || msg.includes("quero fazer") || msg.includes("vou querer") ||
      msg.includes("me vê") || msg.includes("me ve") || msg.includes("me manda") ||
      msg.includes("preciso de") || msg.includes("precisando de")) return "start_order";
  // "Quero [produto]" = pedido
  if (msg.includes("quero") && (msg.includes("bolo") || msg.includes("salgado") || msg.includes("mini") ||
      msg.includes("acai") || msg.includes("açaí") || msg.includes("docinho") || msg.includes("torta") ||
      msg.includes("fatia") || msg.includes("unidade"))) return "start_order";
  // "Quero o de [sabor]" — padrão muito comum
  if (/quero\s+(o\s+de|a\s+de|o|um|uma)\s+/i.test(msg)) return "start_order";
  // Encomenda sem pergunta de preço
  if (msg.includes("encomenda") && !msg.includes("preco") && !msg.includes("valor") && !msg.includes("quanto")) return "start_order";
  // Quantidades diretas: "100 mini salgados", "2kg de brigadeiro"
  if (/\d+\s*(kg|mini|unidade|fatia|cento)/.test(msg) && !msg.includes("quanto") && !msg.includes("preco") && !msg.includes("valor")) return "start_order";

  // ── Respostas de sabor/escolha de bolo (ex: "pode ser de mousse de maracujá", "o bolo de brigadeiro") ──
  // Esses padrões indicam que o cliente está escolhendo/informando sabor dentro de um pedido em andamento
  if (/(?:pode\s+ser|quero|vai\s+ser|faz|seja)\s+(?:de\s+|o\s+de\s+)?/i.test(msg) && msg.includes("bolo")) return "start_order";
  // "pode ser de [sabor]" / "vai ser de [sabor]" — sem "quanto/preço" = está escolhendo, não perguntando preço
  if (/(?:pode\s+ser|vai\s+ser)\s+(?:de\s+|o\s+de\s+)\w/i.test(msg) && !msg.includes("quanto") && !msg.includes("preco") && !msg.includes("valor") && msg.length < 80) return "start_order";
  // "o de [sabor]" ou "de [sabor]" — resposta direta a "qual sabor?"
  if (/^(?:o\s+de|de)\s+[a-záàâãéèêíïóôõúüç]/i.test(msg) && msg.length < 50 && !msg.includes("?")) return "start_order";

  // ── Perguntas de preço ──
  if (msg.includes("preco") || msg.includes("valor") || msg.includes("quanto custa") ||
      msg.includes("quanto fica") || msg.includes("quanto e") || msg.includes("quanto sai") ||
      msg.includes("qual o preco") || msg.includes("qual o valor") || msg.includes("quanto ta") ||
      msg.includes("quanto tá") || msg.includes("tabela") || msg.includes("preço")) return "ask_price";

  // ── Recomendações ──
  if (msg.includes("recomenda") || msg.includes("sugere") || msg.includes("qual bolo") ||
      msg.includes("sugestao") || msg.includes("sugestão") || msg.includes("qual outro") ||
      msg.includes("teria outro") || msg.includes("o que voce indica") || msg.includes("o que tem") ||
      msg.includes("quais sabores") || msg.includes("quais os sabores") || msg.includes("que sabores") ||
      msg.includes("cardapio") || msg.includes("cardápio") || msg.includes("catalogo")) return "ask_recommendation";

  return "other";
}

function deriveStage(
  memory: Record<string, unknown>,
  intent: ConversationIntent,
  fullMessage: string
): ConversationStage {
  const msg = normalizeForCompare(fullMessage);
  const oldStage = (memory.stage as ConversationStage | undefined) || "start";
  const mentionsOrderType = msg.includes("delivery") || msg.includes("retirada") || msg.includes("encomenda");

  // ── Cancelamento / mudança de ideia → reset ao start ──
  const wantsCancel = msg.includes("cancela") || msg.includes("desistir") || msg.includes("desisti") ||
    msg.includes("nao quero mais") || msg.includes("não quero mais") || msg.includes("esquece") ||
    msg.includes("deixa pra la") || msg.includes("deixa pra lá") || msg.includes("recomecar") ||
    msg.includes("recomeçar") || msg.includes("comecar de novo") || msg.includes("começar de novo");
  if (wantsCancel && oldStage !== "start") return "start";

  // Pagamento/comprovante → pós-pagamento
  if (intent === "payment_proof") return "post_payment";

  // Se já está coletando itens ou aguardando tipo, e o intent é start_order → manter collecting_items
  // (cliente está complementando informação, não iniciando pedido do zero)
  if (intent === "start_order" && (oldStage === "collecting_items" || oldStage === "awaiting_order_type")) {
    return mentionsOrderType ? "collecting_items" : oldStage === "collecting_items" ? "collecting_items" : "awaiting_order_type";
  }

  // Início de pedido (novo)
  if (intent === "start_order" && !mentionsOrderType) return "awaiting_order_type";
  if (intent === "start_order" && mentionsOrderType) return "collecting_items";

  // Se está aguardando tipo de pedido e o cliente respondeu com o tipo
  if (oldStage === "awaiting_order_type" && mentionsOrderType) return "collecting_items";

  // Se está coletando itens e o cliente confirma → confirming
  // Evitar falsos positivos: "isso não", "isso não é", "isso errado" NÃO confirmam
  const hasNegation = msg.includes("isso nao") || msg.includes("isso não") || msg.includes("isso errado") || msg.includes("isso ta errado") || msg.includes("não é isso");
  const confirmsOrder = !hasNegation && (msg.includes("isso") || msg.includes("correto") || msg.includes("confirmo") || msg.includes("ta certo") || msg.includes("está certo") || msg.includes("isso mesmo") || msg.includes("isso ai") || msg.includes("pode confirmar"));
  if (oldStage === "collecting_items" && confirmsOrder) return "confirming_order";

  // Se está confirmando e menciona pagamento → awaiting_payment
  if (oldStage === "confirming_order" && (msg.includes("pix") || msg.includes("pagar") || msg.includes("pagamento"))) return "awaiting_payment";

  // Manter etapas estáveis
  if (oldStage === "awaiting_payment" && intent !== "start_order") return "awaiting_payment";
  if (oldStage === "confirming_order" && intent === "other") return "confirming_order";

  // Perguntas de preço ou recomendação durante qualquer etapa → collecting_items
  if (intent === "ask_price" || intent === "ask_recommendation") {
    return oldStage === "start" ? "collecting_items" : oldStage;
  }

  return oldStage;
}

function buildControlHint(
  intent: ConversationIntent,
  stage: ConversationStage,
  memory: Record<string, unknown>
): string {
  const lastIntent = (memory.last_intent as string | undefined) || "none";
  return `[MOTOR_DE_CONTROLE_DE_FLUXO]
- intent_atual: ${intent}
- etapa_atual: ${stage}
- intent_anterior: ${lastIntent}
- regras_chave:
  1) nao inventar produto fora do cardapio
  2) manter contexto continuo da conversa — NUNCA re-perguntar info ja fornecida (peso, sabor, quantidade)
  3) se etapa_atual=awaiting_order_type, perguntar objetivamente: "É para encomenda, delivery ou retirada?"
  4) se etapa_atual=collecting_items, coletar itens e so depois fechar total
  5) resposta curta, humana, direta e com pausa natural
  6) se o cliente informa sabor e peso ja foi dito → combinar e calcular, sem perguntar peso de novo
  7) se o cliente informa peso e sabor ja foi dito → combinar e calcular, sem perguntar sabor de novo
[/MOTOR_DE_CONTROLE_DE_FLUXO]`;
}

function enforceOrderTypeQuestion(
  replyText: string,
  intent: ConversationIntent,
  stage: ConversationStage,
  fullMessage: string
): string {
  if (!replyText) return replyText;
  const msg = normalizeForCompare(fullMessage);
  const hasOrderTypeInUserMsg = msg.includes("delivery") || msg.includes("retirada") || msg.includes("encomenda");
  if (intent !== "start_order" || hasOrderTypeInUserMsg || stage !== "awaiting_order_type") return replyText;
  const rep = normalizeForCompare(replyText);
  if (rep.includes("encomenda") && rep.includes("delivery") && rep.includes("retirada")) return replyText;
  // Verificar se a resposta já pergunta de alguma forma sobre tipo de pedido
  if (rep.includes("retirada") || rep.includes("delivery") || rep.includes("encomenda")) return replyText;
  return `${replyText.trim()}\n\nMe diz: é retirada, delivery ou encomenda? 😊`;
}

function splitAboveFourKg(totalKg: number): number[] {
  const parts: number[] = [];
  let rem = totalKg;
  while (rem > 4) {
    parts.push(4);
    rem -= 4;
  }
  if (rem > 0) parts.push(rem);
  return parts;
}

function extractDecorationRequestFromMessage(fullMessage: string): string | null {
  const text = (fullMessage || "").trim();
  if (!text) return null;
  const norm = normalizeForCompare(text);
  const askedDecoration =
    norm.includes("decoracao") ||
    norm.includes("decorar") ||
    norm.includes("decorado") ||
    norm.includes("topo") ||
    norm.includes("chantininho") ||
    norm.includes("pasta americana");
  if (!askedDecoration) return null;
  return text.slice(0, 300);
}

function applyDecorationToPedidoPayload(
  pedidoJson: Record<string, unknown> | null,
  decorationText: string | null
): Record<string, unknown> | null {
  if (!pedidoJson || !decorationText) return pedidoJson;
  const items = (pedidoJson.items as Array<Record<string, unknown>> | undefined) || [];
  if (items.length === 0) return pedidoJson;
  const mapped = items.map((it) => {
    const note = (typeof it.notes === "string" ? it.notes.trim() : "");
    const line = `Decoração solicitada (mensagem do cliente): "${decorationText}"`;
    if (note) return { ...it, notes: `${note} | ${line}`.slice(0, 500) };
    return { ...it, notes: line.slice(0, 500) };
  });
  return { ...pedidoJson, items: mapped };
}

function applyDecorationToEncomendaPayload(
  encomendaJson: Record<string, unknown> | null,
  decorationText: string | null
): Record<string, unknown> | null {
  if (!encomendaJson || !decorationText) return encomendaJson;
  const obs = typeof encomendaJson.observations === "string" ? encomendaJson.observations.trim() : "";
  const line = `Decoração solicitada (mensagem do cliente): "${decorationText}"`;
  const merged = obs ? `${obs} | ${line}` : line;
  return { ...encomendaJson, observations: merged.slice(0, 500) };
}

function detectCakePriceIntent(
  fullMessage: string,
  recipes: { name: string; whole_price?: number | null; sale_price?: number | null; slice_price?: number | null }[]
): string | null {
  const msgNorm = normalizeForCompare(fullMessage);
  const asksPrice = msgNorm.includes("preco") || msgNorm.includes("valor") || msgNorm.includes("quanto");
  const talksCake = msgNorm.includes("bolo");
  if (!asksPrice || !talksCake || recipes.length === 0) return null;

  const byName = recipes
    .map((r) => ({
      name: r.name,
      norm: normalizeForCompare(r.name),
      price: Number(r.whole_price ?? r.sale_price ?? r.slice_price ?? 0),
    }))
    .filter((r) => r.price > 0)
    .sort((a, b) => b.norm.length - a.norm.length);

  const matched = byName.find((r) => msgNorm.includes(r.norm));
  if (!matched) return null;

  const kgMatch = fullMessage.match(/(\d+(?:[.,]\d+)?)\s*kg/i);
  if (!kgMatch) {
    return `O bolo de ${matched.name} está R$ ${matched.price.toFixed(2)} por kg 😊`;
  }

  const kg = Number((kgMatch[1] || "").replace(",", "."));
  if (!Number.isFinite(kg) || kg <= 0) return null;
  if (!Number.isInteger(kg)) {
    return `Para bolo por kg a gente trabalha com peso inteiro (1kg, 2kg, 3kg ou 4kg por bolo) 😊`;
  }

  if (kg > 4) {
    const parts = splitAboveFourKg(kg);
    const total = kg * matched.price;
    const splitText = parts.map((p) => `${p}kg`).join(" + ");
    return `Para ${kg}kg, dividimos em mais de um bolo por causa do limite da forma: ${splitText}. O valor total fica R$ ${total.toFixed(2)} (R$ ${matched.price.toFixed(2)}/kg).`;
  }

  const total = kg * matched.price;
  return `O bolo de ${matched.name} com ${kg}kg fica R$ ${total.toFixed(2)} (R$ ${matched.price.toFixed(2)}/kg).`;
}

function extractBoloRecommendations(text: string): string[] {
  const out: string[] = [];
  const matches = text.match(/bolo\s+de\s+[a-zA-ZÀ-ÿ0-9\s]+/gi) || [];
  for (const m of matches) {
    const cleaned = m
      .replace(/[.,!?;:()\[\]"]/g, " ")
      .replace(/\s+/g, " ")
      .trim();
    if (cleaned.length >= 8) out.push(cleaned);
  }
  return [...new Set(out)];
}

function hasInvalidRecommendation(replyText: string, recipeNames: string[]): boolean {
  const normalizedRecipes = recipeNames.map((n) => normalizeForCompare(n));
  const candidates = extractBoloRecommendations(replyText).map((c) => normalizeForCompare(c));
  if (candidates.length === 0) return false;
  for (const candidate of candidates) {
    const found = normalizedRecipes.some((r) => r === candidate || r.includes(candidate) || candidate.includes(r));
    if (!found) return true;
  }
  return false;
}

function enforceReplyGuardrails(
  replyText: string,
  recipeNames: string[],
  fullMessage: string
): string {
  if (!replyText || recipeNames.length === 0) return replyText;

  // Verificar QUALQUER menção a "bolo de X" que não existe no cardápio
  // (não só quando pede recomendação — a IA pode alucinar a qualquer momento)
  if (hasInvalidRecommendation(replyText, recipeNames)) {
    const msg = normalizeForCompare(fullMessage);
    const askedRecommendation =
      msg.includes("recomenda") || msg.includes("sugere") || msg.includes("sugestao") ||
      msg.includes("sugestão") || msg.includes("qual bolo") || msg.includes("qual outro") ||
      msg.includes("teria outro") || msg.includes("o que tem");

    if (askedRecommendation) {
      // Era recomendação → resposta focada em sugestões reais
      const top = recipeNames.slice(0, 5).join(", ");
      return `Os mais pedidos aqui são: ${top} 😊\nQuer saber o preço de algum? Ou posso te enviar o cardápio completo: ${CARDAPIO_PDF_URL}`;
    } else {
      // IA inventou sabor numa resposta normal → tentar limpar
      // Substituir a parte inventada por uma versão segura
      const invalidCakes = extractBoloRecommendations(replyText)
        .filter(c => {
          const norm = normalizeForCompare(c);
          return !recipeNames.some(r => {
            const rn = normalizeForCompare(r);
            return rn === norm || rn.includes(norm) || norm.includes(rn);
          });
        });

      let cleaned = replyText;
      for (const inv of invalidCakes) {
        // Remove menções ao bolo inventado
        cleaned = cleaned.replace(new RegExp(inv.replace(/[.*+?^${}()|[\]\\]/g, '\\$&'), 'gi'), '[produto do cardápio]');
      }

      // Se ficou muito alterado, adicionar aviso
      if (invalidCakes.length > 0) {
        const top = recipeNames.slice(0, 4).join(", ");
        cleaned += `\n\nNossos sabores disponíveis incluem: ${top}. Quer ver o cardápio completo?`;
      }
      return cleaned;
    }
  }

  return replyText;
}

async function sendEvolutionMessage(
  baseUrl: string,
  apiKey: string,
  instance: string,
  number: string,
  text: string
): Promise<void> {
  const num = number.replace(/\D/g, "").slice(-15);
  if (!num || num.length < 10 || !text) return;
  if (!isAllowedEvolutionBaseUrl(baseUrl)) throw new Error("Evolution URL inválida (apenas HTTPS permitido)");
  const url = `${baseUrl}/message/sendText/${encodeURIComponent(instance)}`;
  const controller = new AbortController();
  const timeoutId = setTimeout(() => controller.abort(), SEND_MESSAGE_TIMEOUT_MS);
  try {
    const dynamicDelay = Math.min(9000, Math.max(1200, Math.floor(text.length * 24)));
    const res = await fetch(url, {
      method: "POST",
      signal: controller.signal,
      headers: {
        "Content-Type": "application/json",
        "apikey": apiKey,
      },
      body: JSON.stringify({
        number: num,
        text: text.slice(0, 4096),
        delay: dynamicDelay,
        textMessage: { text: text.slice(0, 4096) },
      }),
    });
    if (!res.ok) {
      const err = await res.text();
      throw new Error(`Evolution send failed: ${res.status} ${err.slice(0, 150)}`);
    }
  } finally {
    clearTimeout(timeoutId);
  }
}

async function findOrCreateCustomer(
  supabase: any,
  phone: string,
  name: string
): Promise<string> {
  const normalized = normalizePhone(phone);
  const { data: existing } = await supabase
    .from("customers")
    .select("id")
    .eq("phone", normalized)
    .limit(1)
    .maybeSingle();
  if (existing?.id) return existing.id;
  const { data: existing2 } = await supabase
    .from("customers")
    .select("id")
    .ilike("phone", `%${normalized.slice(-8)}`)
    .limit(1)
    .maybeSingle();
  if (existing2?.id) return existing2.id;
  const remoteJid = normalized || phone;
  const { data: created, error } = await supabase
    .from("customers")
    .insert({
      name: sanitizeName(name) || "WhatsApp",
      phone: normalized || phone,
      remote_jid: remoteJid,
      status: "novo",
    })
    .select("id")
