function getSuggestedLeadStatus(currentStatus: string | null, message: string): string {
  const base = currentStatus || "novo_lead";
  const txt = message.toLowerCase();

  // Conversa já fechada/concluída
  if (
    txt.includes("fechado") ||
    txt.includes("fechou") ||
    txt.includes("confirmo") ||
    txt.includes("confirmar") ||
    txt.includes("pagar") ||
    txt.includes("pagamento") ||
    txt.includes("pix")
  ) {
    // Etapa imediatamente antes de virar cliente no funil visual
    return "proposta_aceita";
  }

  // Cliente pedindo preço, condições ou detalhes do pedido → negociação
  if (
    txt.includes("preço") ||
    txt.includes("preco") ||
    txt.includes("valor") ||
    txt.includes("quanto") ||
    txt.includes("orçamento") ||
    txt.includes("orcamento") ||
    txt.includes("entrega") ||
    txt.includes("horário") ||
    txt.includes("horario") ||
    txt.includes("data")
  ) {
    if (base === "proposta_aceita" || base === "convertido") return base;
    return "em_negociacao";
  }

  // Caso padrão: mantém status atual ou novo_lead
  return base;
}

async function findOrCreateLead(
  supabase: any,
  phone: string,
  name: string,
  message: string
): Promise<string | null> {
  const normalized = normalizePhone(phone);
  const { data: existing } = await supabase
    .from("social_leads")
    .select("id, status")
    .eq("source", "whatsapp")
    .eq("phone", normalized)
    .limit(1)
    .maybeSingle();

  const nextStatus = getSuggestedLeadStatus(existing?.status ?? null, message);
  const now = new Date().toISOString();

  if (existing?.id) {
    // Atualiza estágio se mudou com base na mensagem
    if (nextStatus !== existing.status) {
      await supabase
        .from("social_leads")
        .update({ status: nextStatus, stage_changed_at: now } as any)
        .eq("id", existing.id);
    }
    return existing.id;
  }

  const { data: created, error } = await supabase
    .from("social_leads")
    .insert({
      instagram_handle: "wa_" + (normalized || phone).slice(-10),
      phone: normalized || phone,
      name: sanitizeName(name) || null,
      source: "whatsapp",
      status: nextStatus,
      stage_changed_at: nextStatus !== "novo_lead" ? now : null,
    } as any)
    .select("id")
    .single();

  if (error) return null;
  return created?.id ?? null;
}

const FALLBACK_REPLY = "Obrigado pela mensagem! Em instantes nossa equipe retorna.";

/** Verifica se o cliente tem pedidos abertos (status 'aberto') nas últimas 72h. */
async function checkOpenOrders(
  supabase: any,
  customerPhone: string
): Promise<{ hasOpenOrder: boolean; orderSummary: string }> {
  const since = new Date(Date.now() - 72 * 60 * 60 * 1000).toISOString();
  const { data: openOrders } = await supabase
    .from("orders")
    .select("id, status, customer_name, created_at, order_items(quantity, recipes(name))")
    .eq("customer_phone", customerPhone)
    .eq("status", "aberto")
    .gte("created_at", since)
    .order("created_at", { ascending: false })
    .limit(3);

  if (!openOrders || openOrders.length === 0) {
    // Também checar encomendas pendentes
    const { data: openEncomendas } = await supabase
      .from("encomendas")
      .select("id, product_description, total_value, status, created_at")
      .eq("customer_phone", customerPhone)
      .in("status", ["pendente", "em_producao", "50_pago"])
      .gte("created_at", since)
      .order("created_at", { ascending: false })
      .limit(3);

    if (!openEncomendas || openEncomendas.length === 0) {
      return { hasOpenOrder: false, orderSummary: "" };
    }

    const encomendaItems = openEncomendas.map((e: any) =>
      `- ${e.product_description || "Encomenda"} (R$ ${Number(e.total_value || 0).toFixed(2)}) — status: ${e.status}`
    ).join("\n");
    return {
      hasOpenOrder: true,
      orderSummary: `Encomendas em aberto:\n${encomendaItems}`,
    };
  }

  const orderItems = openOrders.map((o: any) => {
    const items = (o.order_items || [])
      .map((oi: any) => `${oi.quantity}x ${oi.recipes?.name || "item"}`)
      .join(", ");
    return `- Pedido de ${o.created_at?.slice(0, 10) || "?"}: ${items || "itens não detalhados"}`;
  }).join("\n");

  return {
    hasOpenOrder: true,
    orderSummary: `Pedidos em aberto:\n${orderItems}`,
  };
}

/** Extrai blocos [CRIAR_PEDIDO], [CRIAR_ENCOMENDA], [QUITAR_ENCOMENDA], [ATUALIZAR_CLIENTE] e [ALERTA_EQUIPE] da resposta da IA. */
function parseCreateBlocks(reply: string): {
  replyClean: string;
  pedidoJson: Record<string, unknown> | null;
  encomendaJson: Record<string, unknown> | null;
  quitarEncomendaJson: Record<string, unknown> | null;
  atualizarClienteJson: Record<string, unknown> | null;
  alertaEquipeText: string | null;
} {
  let replyClean = reply;
  let pedidoJson: Record<string, unknown> | null = null;
  let encomendaJson: Record<string, unknown> | null = null;
  let quitarEncomendaJson: Record<string, unknown> | null = null;
  let atualizarClienteJson: Record<string, unknown> | null = null;
  let alertaEquipeText: string | null = null;

  const pedidoMatch = reply.match(/\[CRIAR_PEDIDO\]([\s\S]*?)\[\/CRIAR_PEDIDO\]/i);
  if (pedidoMatch) {
    replyClean = replyClean.replace(/\s*\[CRIAR_PEDIDO\][\s\S]*?\[\/CRIAR_PEDIDO\]\s*/gi, "").trim();
    try {
      pedidoJson = JSON.parse(pedidoMatch[1].trim()) as Record<string, unknown>;
    } catch {
      pedidoJson = null;
    }
  }

  const encomendaMatch = reply.match(/\[CRIAR_ENCOMENDA\]([\s\S]*?)\[\/CRIAR_ENCOMENDA\]/i);
  if (encomendaMatch) {
    replyClean = replyClean.replace(/\s*\[CRIAR_ENCOMENDA\][\s\S]*?\[\/CRIAR_ENCOMENDA\]\s*/gi, "").trim();
    try {
      encomendaJson = JSON.parse(encomendaMatch[1].trim()) as Record<string, unknown>;
    } catch {
      encomendaJson = null;
    }
  }

  const quitarMatch = reply.match(/\[QUITAR_ENCOMENDA\]([\s\S]*?)\[\/QUITAR_ENCOMENDA\]/i);
  if (quitarMatch) {
    replyClean = replyClean.replace(/\s*\[QUITAR_ENCOMENDA\][\s\S]*?\[\/QUITAR_ENCOMENDA\]\s*/gi, "").trim();
    try {
      quitarEncomendaJson = JSON.parse(quitarMatch[1].trim()) as Record<string, unknown>;
    } catch {
      quitarEncomendaJson = null;
    }
  }

  const atualizarMatch = reply.match(/\[ATUALIZAR_CLIENTE\]([\s\S]*?)\[\/ATUALIZAR_CLIENTE\]/i);
  if (atualizarMatch) {
    replyClean = replyClean.replace(/\s*\[ATUALIZAR_CLIENTE\][\s\S]*?\[\/ATUALIZAR_CLIENTE\]\s*/gi, "").trim();
    try {
      atualizarClienteJson = JSON.parse(atualizarMatch[1].trim()) as Record<string, unknown>;
    } catch {
      atualizarClienteJson = null;
    }
  }

  // NOVO: Extrair bloco [ALERTA_EQUIPE]
  const alertaMatch = reply.match(/\[ALERTA_EQUIPE\]([\s\S]*?)\[\/ALERTA_EQUIPE\]/i);
  if (alertaMatch) {
    replyClean = replyClean.replace(/\s*\[ALERTA_EQUIPE\][\s\S]*?\[\/ALERTA_EQUIPE\]\s*/gi, "").trim();
    alertaEquipeText = alertaMatch[1].trim() || null;
  }

  return { replyClean, pedidoJson, encomendaJson, quitarEncomendaJson, atualizarClienteJson, alertaEquipeText };
}

/** Obtém operator_id para pedidos criados pelo bot: automático (primeiro perfil) ou crm_settings bot_operator_id. */
async function getBotOperatorId(supabase: any): Promise<string | null> {
  const { data: settings } = await supabase.from("crm_settings").select("value").eq("key", "bot_operator_id").maybeSingle();
  const uid = (settings as { value?: string } | null)?.value?.trim();
  if (uid) return uid;
  const { data: profile } = await supabase.from("profiles").select("id").order("created_at", { ascending: true }).limit(1).maybeSingle();
  return (profile as { id?: string } | null)?.id ?? null;
}

/** Cria pedido + itens + venda na plataforma a partir do JSON emitido pela IA (após comprovante). */
async function createOrderFromPayload(
  supabase: any,
  payload: Record<string, unknown>,
  customerPhone: string,
  customerName: string,
  evo: { baseUrl: string; apiKey: string; instance: string },
  ownerPhones: string[]
): Promise<{ ok: boolean; orderId?: string; error?: string }> {
  const operatorId = await getBotOperatorId(supabase);
  if (!operatorId) {
    console.error("createOrderFromPayload: nenhum operator_id (bot_operator_id ou profile)");
    return { ok: false, error: "operator_id não configurado" };
  }

  const items = (payload.items as { recipe_name?: string; quantity?: number; unit_type?: string; notes?: string }[]) || [];
  if (items.length === 0) return { ok: false, error: "itens vazios" };

  const { data: recipes } = await supabase
    .from("recipes")
    .select("id, name, sale_price, slice_price, whole_price, slice_weight_grams, whole_weight_grams")
    .eq("active", true);
  const recipeMap = new Map<
    string,
    { id: string; sale_price: number; slice_price: number | null; whole_price: number | null; slice_weight_grams: number | null; whole_weight_grams: number | null }
  >();
  for (const r of recipes || []) {
    const name = (r as { name: string }).name?.trim().toLowerCase();
    if (name) recipeMap.set(name, {
      id: (r as { id: string }).id,
      sale_price: Number((r as { sale_price?: number }).sale_price) || 0,
      slice_price: (r as { slice_price?: number }).slice_price != null ? Number((r as { slice_price: number }).slice_price) : null,
      whole_price: (r as { whole_price?: number }).whole_price != null ? Number((r as { whole_price: number }).whole_price) : null,
      slice_weight_grams: (r as { slice_weight_grams?: number | null }).slice_weight_grams ?? null,
      whole_weight_grams: (r as { whole_weight_grams?: number | null }).whole_weight_grams ?? null,
    });
  }

  const orderItems: { recipe_id: string; quantity: number; unit_price: number; unit_type: string; notes: string | null }[] = [];
  for (const item of items) {
    const name = String(item.recipe_name || "").trim().toLowerCase();
    let recipeEntry = recipeMap.get(name) ?? null;
    if (!recipeEntry && name) {
      for (const [k, v] of recipeMap.entries()) {
        if (k.includes(name) || name.includes(k)) {
          recipeEntry = v;
          break;
        }
      }
    }
    if (!recipeEntry) continue;
    const unitType = (item.unit_type || "slice").toLowerCase() === "whole" ? "whole" : "slice";
    const unitPrice = unitType === "whole" && recipeEntry.whole_price != null ? recipeEntry.whole_price : (recipeEntry.slice_price ?? recipeEntry.sale_price);
    const qty = Math.max(1, Math.floor(Number(item.quantity) || 1));
    orderItems.push({
      recipe_id: recipeEntry.id,
      quantity: qty,
      unit_price: unitPrice,
      unit_type: unitType,
      notes: (item.notes && String(item.notes).trim()) || null,
    });
  }
  if (orderItems.length === 0) return { ok: false, error: "nenhum item válido" };

  const channel = (payload.channel as string) || "cardapio_digital";
  // Resolver delivery_zone_id a partir do bairro informado pela IA
  let deliveryZoneId: string | null = null;
  const bairroPayload = ((payload.bairro as string) || "").trim();
  if (bairroPayload && channel === "delivery") {
    const { data: zoneMatch } = await supabase
      .from("delivery_zones")
      .select("id")
      .ilike("bairro", bairroPayload)
      .eq("ativo", true)
      .limit(1)
      .maybeSingle();
    deliveryZoneId = (zoneMatch as { id?: string } | null)?.id ?? null;
  }

  const { data: order, error: orderErr } = await supabase
    .from("orders")
    .insert({
      operator_id: operatorId,
      order_number: (payload.order_number as string) || null,
      table_number: (payload.table_number as string) || null,
      customer_name: (payload.customer_name as string) || customerName || "Cliente WhatsApp",
      customer_phone: customerPhone || null,
      channel: channel === "delivery" ? "delivery" : channel === "balcao" ? "balcao" : "cardapio_digital",
      status: "aberto",
      delivery_status: channel === "delivery" ? "recebido" : null,
      delivery_zone_id: deliveryZoneId,
    } as Record<string, unknown>)
    .select("id")
    .single();

  if (orderErr || !order) {
    console.error("createOrderFromPayload order insert:", orderErr);
    return { ok: false, error: (orderErr as Error)?.message };
  }

  const orderId = (order as { id: string }).id;

  // Tentar vincular cada item a um lote de estoque (inventory) para poder dar baixa automática.
  const orderItemsWithInventory: {
    recipe_id: string;
    quantity: number;
    unit_price: number;
    unit_type: string;
    notes: string | null;
    inventory_id: string | null;
  }[] = [];
  for (const i of orderItems) {
    const { data: inv } = await supabase
      .from("inventory")
      .select("id")
      .eq("recipe_id", i.recipe_id)
      .gt("stock_grams", 0)
      .order("produced_at", { ascending: false })
      .limit(1)
      .maybeSingle();
    orderItemsWithInventory.push({
      ...i,
      inventory_id: (inv as { id?: string } | null)?.id ?? null,
    });
  }

  const toInsert = orderItemsWithInventory.map((i) => ({
    order_id: orderId,
    recipe_id: i.recipe_id,
    inventory_id: i.inventory_id,
    quantity: i.quantity,
    unit_price: i.unit_price,
    subtotal: i.quantity * i.unit_price,
    unit_type: i.unit_type,
    notes: i.notes,
  }));
  const { error: itemsErr } = await supabase.from("order_items").insert(toInsert as Record<string, unknown>[]);
  if (itemsErr) {
    console.error("createOrderFromPayload order_items insert:", itemsErr);
    return { ok: false, error: (itemsErr as Error)?.message };
  }

  const total = orderItemsWithInventory.reduce((s, i) => s + i.quantity * i.unit_price, 0);
  const paymentRaw = ((payload.payment_method as string) || "pix").toLowerCase();
  const payment_method =
    paymentRaw === "credito" || paymentRaw === "crédito"
      ? "credito"
      : paymentRaw === "debito" || paymentRaw === "débito"
        ? "debito"
        : paymentRaw === "dinheiro"
          ? "dinheiro"
          : paymentRaw === "refeicao" || paymentRaw === "refeição"
            ? "refeicao"
            : "pix";

  // Registrar venda (sales) ligada a esse pedido.
  const soldAt = new Date().toISOString();
  const { data: sale, error: saleErr } = await supabase
    .from("sales")
    .insert({
      operator_id: operatorId,
      channel: channel === "delivery" ? "delivery" : channel === "balcao" ? "balcao" : "cardapio_digital",
      payment_method: payment_method as any,
      total,
      order_number: (payload.order_number as string) || null,
      table_number: (payload.table_number as string) || null,
      customer_name: (payload.customer_name as string) || customerName || "Cliente WhatsApp",
      customer_id: null,
      sold_at: soldAt,
    } as Record<string, unknown>)
    .select("id")
    .single();
  if (saleErr || !sale) {
    console.error("createOrderFromPayload sale insert:", saleErr);
    return { ok: false, error: (saleErr as Error)?.message };
  }
  const saleId = (sale as { id: string }).id;

  const saleItems = orderItemsWithInventory.map((i) => ({
    sale_id: saleId,
    recipe_id: i.recipe_id,
    inventory_id: i.inventory_id,
    quantity: i.quantity,
    unit_price: i.unit_price,
    subtotal: i.quantity * i.unit_price,
    unit_type: i.unit_type,
  }));
  const { error: siErr } = await supabase.from("sale_items").insert(saleItems as Record<string, unknown>[]);
  if (siErr) {
    console.error("createOrderFromPayload sale_items insert:", siErr);
    return { ok: false, error: (siErr as Error)?.message };
  }

  // Envia pedido para a plataforma de notas (TicketFlow) sem bloquear o fluxo principal.
  try {
    const itemsForTicket = orderItemsWithInventory.map((i) => {
      const recipe = (recipes || []).find((r: any) => (r as { id: string }).id === i.recipe_id) as { name?: string } | undefined;
      const name = (recipe?.name || "produto").toString();
      return {
        name,
        quantity: i.quantity,
        unit_price: i.unit_price,
        subtotal: i.quantity * i.unit_price,
      };
    });
    await sendTicketFlowOrder(supabase as any, customerPhone, {
      type: "pedido",
      external_id: orderId,
      channel: channel === "delivery" ? "delivery" : channel === "balcao" ? "retirada" : "cardapio_digital",
      total,
      payment_method,
      items: itemsForTicket,
    } as any);
  } catch (e) {
    console.error("createOrderFromPayload ticketflow error:", (e as Error).message);
  }

  // Dar baixa no estoque (inventory.stock_grams / slices_available) e, se estiver acabando, avisar donos no WhatsApp.
  for (const i of orderItemsWithInventory) {
    if (!i.inventory_id) continue;
    const recipeEntry = [...recipeMap.values()].find((r) => r.id === i.recipe_id);
    if (!recipeEntry) continue;
    const unitWeight =
      i.unit_type === "whole"
        ? Number(recipeEntry.whole_weight_grams) || 0
        : Number(recipeEntry.slice_weight_grams) || 0;
    const weightToDeduct = unitWeight * i.quantity;

    const { data: inv } = await supabase
      .from("inventory")
      .select("stock_grams, slices_available")
      .eq("id", i.inventory_id)
      .maybeSingle();
    if (!inv) continue;
    const invAny = inv as { stock_grams?: number | null; slices_available: number };
    const currentGrams = Number(invAny.stock_grams ?? 0);
    const currentSlices = Number(invAny.slices_available ?? 0);
    const newGrams = Math.max(0, currentGrams - weightToDeduct);
    const newSlices = Math.max(0, currentSlices - i.quantity);

    await supabase
      .from("inventory")
      .update({ stock_grams: newGrams, slices_available: newSlices } as Record<string, unknown>)
      .eq("id", i.inventory_id);

    // Se poucas fatias restarem, avisa os donos por WhatsApp.
    if (ownerPhones.length > 0 && newSlices <= 3 && currentSlices > newSlices) {
      const recipeNameKey = [...recipeMap.entries()].find(([, v]) => v.id === i.recipe_id)?.[0] ?? "";
      const recipeName =
        (recipes || []).find((r: any) => (r as { name: string; id: string }).id === i.recipe_id)?.name ||
        recipeNameKey ||
        "produto";
      const alertText = `Alerta de estoque: o produto \"${recipeName}\" está acabando. Restam aproximadamente ${newSlices} fatia(s).`;
      for (const ownerPhone of ownerPhones) {
        try {
          await sendEvolutionMessage(evo.baseUrl, evo.apiKey, evo.instance, ownerPhone, alertText);
        } catch (e) {
          console.error("low-stock alert send error:", (e as Error).message);
        }
      }
    }
  }

  // Marca pedido como finalizado, já que o pagamento foi confirmado no WhatsApp.
  const { error: closeErr } = await supabase
    .from("orders")
    .update({ status: "finalizado" as any, closed_at: new Date().toISOString() })
    .eq("id", orderId);
  if (closeErr) {
    console.error("createOrderFromPayload close order error:", closeErr);
  }

  return { ok: true, orderId };
}

/** Cria encomenda na plataforma a partir do JSON emitido pela IA (após comprovante 50%). */
async function createEncomendaFromPayload(
  supabase: any,
  payload: Record<string, unknown>
): Promise<{ ok: boolean; encomendaId?: string; error?: string }> {
  const customer_name = (payload.customer_name as string)?.trim() || "Cliente WhatsApp";
  const product_description = (payload.product_description as string)?.trim() || "Encomenda";
  const quantity = Math.max(1, Math.floor(Number(payload.quantity) || 1));
  const total_value = Math.max(0, Number(payload.total_value) || 0);
  const payment_method = (payload.payment_method as string)?.toLowerCase() === "credito" ? "credito" : "pix";
  const paid_50_percent = !!payload.paid_50_percent;

  // Resolver delivery_zone_id a partir do endereço (bairro)
  let encZoneId: string | null = null;
  const encAddress = ((payload.address as string) || "").trim();
  if (encAddress) {
    // Tenta encontrar o bairro no endereço
    const { data: zones } = await supabase.from("delivery_zones").select("id, bairro").eq("ativo", true);
    if (zones) {
      const addrLower = encAddress.toLowerCase();
      const match = (zones as { id: string; bairro: string }[]).find((z) => addrLower.includes(z.bairro.toLowerCase()));
      encZoneId = match?.id ?? null;
    }
  }

  const { data: enc, error } = await supabase
    .from("encomendas")
    .insert({
      customer_name,
      customer_phone: (payload.customer_phone as string) || null,
      product_description,
      quantity,
      total_value,
      address: encAddress || null,
      payment_method,
      paid_50_percent,
      observations: (payload.observations as string) || null,
      delivery_date: (payload.delivery_date as string) || null,
      delivery_time_slot: (payload.delivery_time_slot as string) || null,
      status: paid_50_percent ? "50_pago" : "pendente",
      source: "whatsapp",
      delivery_zone_id: encZoneId,
    } as Record<string, unknown>)
    .select("id")
    .single();

  if (error || !enc) {
    console.error("createEncomendaFromPayload:", error);
    return { ok: false, error: (error as Error)?.message };
  }

  // Opcional: registra faturamento da entrada (50% ou valor cheio) como venda simples,
  // para aparecer nos relatórios mesmo sem itens detalhados.
  try {
    const operatorId = await getBotOperatorId(supabase);
    if (operatorId && total_value > 0) {
      const soldAt = new Date().toISOString();
      const depositTotal = paid_50_percent ? total_value / 2 : total_value;
      await supabase.from("sales").insert({
        operator_id: operatorId,
        channel: "balcao",
        payment_method: payment_method as any,
        total: depositTotal,
        order_number: null,
        table_number: null,
        customer_name,
        customer_id: null,
        sold_at: soldAt,
      } as Record<string, unknown>);
    }
  } catch (e) {
    console.error("createEncomendaFromPayload sales insert error:", (e as Error).message);
  }

  // Envia encomenda para a plataforma de notas (TicketFlow) sem bloquear o fluxo principal.
  try {
    await sendTicketFlowOrder(supabase as any, (payload.customer_phone as string) || "", {
      type: "encomenda",
      external_id: (enc as { id: string }).id,
      channel: "encomenda",
      total: total_value,
      payment_method,
      items: [
        {
          name: product_description,
          quantity,
          unit_price: total_value / quantity,
          subtotal: total_value,
        },
      ],
    } as any);
  } catch (e) {
    console.error("createEncomendaFromPayload ticketflow error:", (e as Error).message);
  }

  return { ok: true, encomendaId: (enc as { id: string }).id };
}

/** Quita o restante de uma encomenda (outros 50%), localizando pela combinação telefone + encomenda anterior. */
async function settleEncomendaFromPayload(
  supabase: any,
  payload: Record<string, unknown>,
  customerPhone: string
): Promise<{ ok: boolean; encomendaId?: string; error?: string }> {
  const normalizedPhone = sanitizePhone((payload.customer_phone as string) || customerPhone);
  const paymentValue = Number(payload.payment_value ?? 0);
  const paymentDateRaw = (payload.payment_date as string | undefined)?.trim();
  if (!normalizedPhone || paymentValue <= 0 || !paymentDateRaw) {
    return { ok: false, error: "dados insuficientes para quitar encomenda" };
  }

  // Segurança: só aceita pagamento do dia corrente.
  const today = new Date();
  const todayStr = today.toISOString().slice(0, 10);
  if (paymentDateRaw !== todayStr) {
    console.warn("settleEncomendaFromPayload: payment_date diferente de hoje", paymentDateRaw, todayStr);
    return { ok: false, error: "data do comprovante não é de hoje" };
  }

  // Encontra a encomenda mais recente desse telefone com 50% já pagos e ainda não cancelada.
  const { data: encomendas } = await supabase
    .from("encomendas")
    .select("id, customer_phone, total_value, paid_50_percent, status")
    .eq("customer_phone", normalizedPhone)
    .eq("paid_50_percent", true)
    .neq("status", "cancelado")
    .order("created_at", { ascending: false })
    .limit(3);

  if (!encomendas || encomendas.length === 0) {
    return { ok: false, error: "nenhuma encomenda pendente encontrada para esse telefone" };
  }

  // Tenta casar pelo valor esperado do restante (aprox. metade do total).
  let target = encomendas[0] as { id: string; total_value: number; paid_50_percent: boolean; status: string };
  const candidates = encomendas as { id: string; total_value: number; paid_50_percent: boolean; status: string }[];
  const match = candidates.find((e) => {
    const total = Number(e.total_value || 0);
    if (!total || total <= 0) return false;
    const expectedRest = total / 2;
    const diff = Math.abs(expectedRest - paymentValue);
    // Aceita diferença de até 1 real para arredondamentos.
    return diff <= 1;
  });
  if (match) target = match;

  const total = Number(target.total_value || 0);
  const expectedRest = total > 0 ? total / 2 : paymentValue;

  // Se o valor está muito diferente do esperado (mais de 20% de diferença), não quita automaticamente.
  if (expectedRest > 0) {
    const diffPerc = Math.abs(paymentValue - expectedRest) / expectedRest;
    if (diffPerc > 0.2) {
      console.warn("settleEncomendaFromPayload: valor pago não bate com o restante esperado", {
        paymentValue,
        expectedRest,
      });
      return { ok: false, error: "valor não confere com o restante esperado" };
    }
  }

  // Atualiza a encomenda para status "entregue" (considerando que o restante é normalmente pago na entrega).
  const { error: updErr } = await supabase
    .from("encomendas")
    .update({ status: "entregue" as any })
    .eq("id", target.id);
  if (updErr) {
    console.error("settleEncomendaFromPayload update encomenda error:", updErr);
    return { ok: false, error: (updErr as Error)?.message };
  }

  // Registra a entrada dos outros 50% em sales.
  try {
    const operatorId = await getBotOperatorId(supabase);
    if (operatorId && paymentValue > 0) {
      await supabase.from("sales").insert({
        operator_id: operatorId,
        channel: "balcao",
        payment_method: "pix",
        total: paymentValue,
        order_number: null,
        table_number: null,
        customer_name: null,
        customer_id: null,
        sold_at: new Date().toISOString(),
      } as Record<string, unknown>);
    }
  } catch (e) {
    console.error("settleEncomendaFromPayload sales insert error:", (e as Error).message);
  }

  return { ok: true, encomendaId: target.id };
}

// ─────────────────────────────────────────────────────────────
// DEBOUNCE: Agrupar mensagens rápidas do WhatsApp
// No WhatsApp é muito comum as pessoas mandarem várias mensagens seguidas.
// Em vez de responder cada uma, esperamos uns segundos e juntamos tudo.
// ─────────────────────────────────────────────────────────────

/**
 * Debounce ATÔMICO via RPC Postgres (SELECT ... FOR UPDATE).
 * Resolve race condition: garante que apenas UM request se torna "líder".
 * Mensagens subsequentes são adicionadas ao buffer sem criar novos líderes.
 */
async function debounceMessage(
  supabase: any,
  remoteJid: string,
  messageText: string
): Promise<{ shouldProcess: boolean; allMessages: string[] }> {
  // 1. Chamar RPC atômico — Postgres decide quem é líder com FOR UPDATE
  const { data: addResult, error: addErr } = await supabase.rpc("debounce_add_message", {
    p_remote_jid: remoteJid,
    p_message: messageText,
    p_debounce_ms: DEBOUNCE_MS,
  });

  if (addErr) {
    // Fallback: se RPC não existe ainda (migration pendente), processar direto sem debounce
    console.warn("debounce_add_message RPC error (migration pendente?):", addErr.message);
    return { shouldProcess: true, allMessages: [messageText] };
  }

  const isLeader = (addResult as { is_leader?: boolean })?.is_leader ?? true;
  const debounceMs = (addResult as { debounce_ms?: number })?.debounce_ms ?? DEBOUNCE_MS;

  if (!isLeader) {
    // Outro request é o líder — esta mensagem já está no buffer
    return { shouldProcess: false, allMessages: [] };
  }

  // 2. Somos o líder — esperar o período de debounce
  await new Promise((resolve) => setTimeout(resolve, debounceMs));

  // 3. Coletar TODAS as mensagens que chegaram durante a espera (atômico)
  const { data: messages, error: collectErr } = await supabase.rpc("debounce_collect_messages", {
    p_remote_jid: remoteJid,
  });

  if (collectErr) {
    console.warn("debounce_collect_messages RPC error:", collectErr.message);
    return { shouldProcess: true, allMessages: [messageText] };
  }

  const allMessages: string[] = Array.isArray(messages) ? messages.filter((m: unknown) => typeof m === "string") : [messageText];

  // Se por algum motivo ficou vazio, pelo menos processar a mensagem original
  if (allMessages.length === 0) {
    return { shouldProcess: true, allMessages: [messageText] };
  }

  return { shouldProcess: true, allMessages };
}

serve(async (req) => {
  if (req.method === "OPTIONS") return new Response(null, { headers: corsHeaders });

  const supabaseUrl = Deno.env.get("SUPABASE_URL")!;
  const serviceKey = Deno.env.get("SUPABASE_SERVICE_ROLE_KEY")!;
  const supabase = createClient<any>(supabaseUrl, serviceKey);

  try {
    const rawBody = await req.json().catch(() => ({}));
    const payload = rawBody as Record<string, unknown>;

    const event = (payload.event as string) || "";
    const data = (payload.data as Record<string, unknown>) || payload;

    const isMessagesEvent =
      !event ||
      event === "MESSAGES_UPSERT" ||
      event === "messages-upsert" ||
      event === "messages.upsert" ||
      event.toLowerCase().includes("message");
    if (event && !isMessagesEvent) {
      return new Response(JSON.stringify({ ok: true, ignored: event }), {
        status: 200,
        headers: { ...corsHeaders, "Content-Type": "application/json" },
      });
    }

    const key = (data.key as { fromMe?: boolean } | undefined) || (payload.key as { fromMe?: boolean } | undefined);
    if (key?.fromMe === true) {
      return new Response(JSON.stringify({ ok: true, ignored: "fromMe" }), {
        status: 200,
        headers: { ...corsHeaders, "Content-Type": "application/json" },
      });
    }

    const messageId = extractMessageId(data) || extractMessageId(payload as Record<string, unknown>);
    if (messageId) {
      const { data: existing } = await supabase
        .from("webhook_processed_events")
        .select("id")
        .eq("id", messageId)
        .maybeSingle();
      if (existing?.id) {
        return new Response(JSON.stringify({ ok: true, duplicate: true }), {
          status: 200,
          headers: { ...corsHeaders, "Content-Type": "application/json" },
        });
      }
    }

    // Fetch settings including ia_paused
    const { data: settingsRows } = await supabase.from("crm_settings").select("key, value").in("key", [...EVOLUTION_KEYS, "ia_paused"]);
    const evo = getEvolutionConfig(settingsRows || []);

    // ── Validar instância: só responder se o payload vier da instância configurada ──
    const payloadInstance = (
      (data as Record<string, unknown>).instance ||
      (data as Record<string, unknown>).instanceName ||
      (payload as Record<string, unknown>).instance ||
      (payload as Record<string, unknown>).instanceName ||
      ""
    ) as string;
    if (
      evo.instance &&
      evo.instance !== "default" &&
      payloadInstance &&
      payloadInstance !== evo.instance
    ) {
      console.log(`[webhook] Ignorando: instância do payload "${payloadInstance}" ≠ configurada "${evo.instance}"`);
      return new Response(JSON.stringify({ ok: true, ignored: "wrong_instance" }), {
        status: 200,
        headers: { ...corsHeaders, "Content-Type": "application/json" },
      });
    }
    const headerSecret = req.headers.get("x-webhook-secret") || req.headers.get("authorization")?.replace(/^Bearer\s+/i, "") || null;
    const querySecret = new URL(req.url || "", "http://x").searchParams.get("secret");
    if (!verifyWebhookSecret(evo.webhookSecret, headerSecret, querySecret)) {
      return new Response(JSON.stringify({ ok: false, error: "Unauthorized" }), {
        status: 401,
        headers: { ...corsHeaders, "Content-Type": "application/json" },
      });
    }

    const keyForJid = data.key ?? payload.key;
    const dataForExtract = keyForJid ? { ...data, key: keyForJid } : data;
    const remoteJid = extractRemoteJid(dataForExtract);
    const normalizedPhone = sanitizePhone(remoteJid);
    if (!normalizedPhone) {
      return new Response(JSON.stringify({ ok: true, invalidPhone: true }), {
        status: 200,
        headers: { ...corsHeaders, "Content-Type": "application/json" },
      });
    }

    const fullPayload = (data.message ? data : payload) as Record<string, unknown>;
    let messageText = sanitizeMessage(extractMessageText(fullPayload));
    let pdfText = "";
    if (hasPdfDocument(fullPayload)) {
      const pdfBytes = await getDocumentBytes(fullPayload, { baseUrl: evo.baseUrl, apiKey: evo.apiKey, instance: evo.instance });
      if (pdfBytes) pdfText = await extractTextFromPdf(pdfBytes);
    }
    const fullMessage = pdfText
      ? (messageText ? `${messageText}\n\n[Conteúdo do PDF anexado]:\n${pdfText}` : `O usuário enviou um documento PDF.\n\n[Conteúdo do PDF]:\n${pdfText}`)
      : messageText;
    if (!fullMessage || !fullMessage.trim()) {
      return new Response(JSON.stringify({ ok: true, noText: true }), {
        status: 200,
        headers: { ...corsHeaders, "Content-Type": "application/json" },
      });
    }

    if (!evo.baseUrl || !evo.apiKey) {
      return new Response(JSON.stringify({ ok: false, error: "Evolution not configured" }), {
        status: 200,
        headers: { ...corsHeaders, "Content-Type": "application/json" },
      });
    }
    if (!isAllowedEvolutionBaseUrl(evo.baseUrl)) {
      return new Response(JSON.stringify({ ok: false, error: "Invalid Evolution URL" }), {
        status: 200,
        headers: { ...corsHeaders, "Content-Type": "application/json" },
      });
    }

    if (messageId) {
      try { await supabase.from("webhook_processed_events").insert({ id: messageId }); } catch (_) {}
    }

    const owner = await getOwner(supabase);
    const { data: ownerSettingsRows } = await supabase.from("crm_settings").select("key, value").in("key", ["owner_phones", "owner_phone_override"]);
    const ownerPhonesMap = new Map((ownerSettingsRows || []).map((r: { key: string; value: string }) => [r.key, r.value]));
    const combined = [ownerPhonesMap.get("owner_phones"), ownerPhonesMap.get("owner_phone_override")].filter(Boolean).join("\n");
    let ownerPhonesList = parseOwnerPhonesList(combined);
    if (owner?.ownerPhone) {
      const n = normalizePhone(owner.ownerPhone);
      if (n.length >= 10 && !ownerPhonesList.includes(n)) ownerPhonesList = [...ownerPhonesList, n];
    }
    const isOwner = ownerPhonesList.length > 0 && isOwnerPhoneInList(normalizedPhone, ownerPhonesList);

    const pushName = sanitizeName((data.pushName as string) || "");

    // Check ia_paused setting
    const allSettingsMap = new Map((settingsRows || []).map((r: { key: string; value: string }) => [r.key, r.value]));
    const iaPaused = (allSettingsMap.get("ia_paused") || "false").toLowerCase() === "true";

    let reply: string;
    try {
      if (isOwner) {
        // ===== MELHORIA 2: Buscar histórico do dono de messaages log =====
        const { data: ownerHistRows } = await supabase
          .from("messaages log")
          .select("from_me, text")
          .eq("remote_jid", remoteJid)
          .order("id", { ascending: false })
          .limit(12);
        const ownerHistory = (ownerHistRows || [])
          .reverse()
          .map((m: { from_me: boolean | null; text: string | null }) => ({
            role: m.from_me ? "assistant" as const : "user" as const,
            content: (m.text || "").slice(0, 4096),
          }));

        // Salvar mensagem de entrada do dono
        await supabase.from("messaages log").insert({
          remote_jid: remoteJid,
          from_me: false,
          text: fullMessage.slice(0, 4096),
        });

        reply = await runAssistente(supabase, fullMessage, ownerHistory);

        // Salvar resposta de saída para o dono
        await supabase.from("messaages log").insert({
          remote_jid: remoteJid,
          from_me: true,
          text: reply.slice(0, 4096),
        });
      } else {
        const customerId = await findOrCreateCustomer(supabase, normalizedPhone, pushName);
        await findOrCreateLead(supabase, normalizedPhone, pushName, fullMessage);
        const { data: recipeRows } = await supabase
          .from("recipes")
          .select("name, whole_price, sale_price, slice_price")
          .eq("active", true);
        const recipeRowsTyped = ((recipeRows || []) as { name?: string; whole_price?: number | null; sale_price?: number | null; slice_price?: number | null }[])
          .filter((r) => !!r.name);
        const recipeNames = recipeRowsTyped
          .map((r) => (r.name || "").trim())
          .filter((n) => n.length > 0);

        await supabase.from("crm_messages").insert({
          customer_id: customerId,
          message_type: "whatsapp_entrada",
          message_content: fullMessage.slice(0, 4096),
          status: "lida",
          sent_at: new Date().toISOString(),
        });

        // ===== MELHORIA 3: Verificar ia_paused =====
        if (iaPaused) {
          return new Response(JSON.stringify({ ok: true, paused: true }), {
            status: 200,
            headers: { ...corsHeaders, "Content-Type": "application/json" },
          });
        }

        // ===== DEBOUNCE: Agrupar mensagens rápidas =====
        // No WhatsApp as pessoas mandam várias mensagens seguidas (ex: "Oi" / "quero pedir" / "bolo de 4kg")
        // Esperamos uns segundos e juntamos tudo antes de responder
        const debounceResult = await debounceMessage(supabase, remoteJid, fullMessage);
        if (!debounceResult.shouldProcess) {
          // Outro request já está aguardando e vai processar todas as mensagens juntas
          console.log("evolution-webhook: mensagem adicionada ao buffer de debounce para", remoteJid);
          return new Response(JSON.stringify({ ok: true, debounced: true }), {
            status: 200,
            headers: { ...corsHeaders, "Content-Type": "application/json" },
          });
        }

        // Combinar todas as mensagens do debounce em uma só
        const combinedMessage = debounceResult.allMessages.length > 1
          ? debounceResult.allMessages.join("\n")
          : fullMessage;

        // Se tiveram mensagens extras do debounce, salvar elas também no histórico
        if (debounceResult.allMessages.length > 1) {
          // As mensagens extras (além da primeira) que chegaram durante o debounce
          const extraMessages = debounceResult.allMessages.slice(1);
          for (const extraMsg of extraMessages) {
            if (extraMsg !== fullMessage) {
              await supabase.from("crm_messages").insert({
                customer_id: customerId,
                message_type: "whatsapp_entrada",
                message_content: extraMsg.slice(0, 4096),
                status: "lida",
                sent_at: new Date().toISOString(),
              });
            }
          }
          console.log(`evolution-webhook: ${debounceResult.allMessages.length} mensagens agrupadas para`, remoteJid);
        }

        // ===== MELHORIA 1: Carregar sessão de conversa =====
        const { data: sessionRow } = await supabase
          .from("sessions")
          .select("*")
          .eq("remote_jid", remoteJid)
          .maybeSingle();

        // Expirar sessões com mais de 24h para evitar contexto obsoleto/antigo
        let sessionMemory: Record<string, unknown> = {};
        let sessionExpired = false;
        if (sessionRow) {
          const updatedAt = sessionRow.updated_at ? new Date(sessionRow.updated_at).getTime() : 0;
          const now = Date.now();
          const TWENTY_FOUR_HOURS = 24 * 60 * 60 * 1000;
          if (updatedAt > 0 && (now - updatedAt) > TWENTY_FOUR_HOURS) {
            // Sessão expirada: limpar memory
            await supabase.from("sessions").update({ memory: {}, updated_at: new Date().toISOString() } as any).eq("remote_jid", remoteJid);
            console.log("evolution-webhook: sessão expirada (>24h), memory limpa para", remoteJid);
            sessionExpired = true;
          } else {
            sessionMemory = (sessionRow.memory as Record<string, unknown>) || {};
          }
        }

        const { data: historyRows } = await supabase
          .from("crm_messages")
          .select("message_type, message_content, created_at")
          .eq("customer_id", customerId)
          .order("created_at", { ascending: false })
          .limit(20);

        let history =
          (historyRows || [])
            .reverse()
            .map((m: { message_type: string; message_content: string | null; created_at?: string }) => {
              const role = m.message_type === "whatsapp_saida" ? "assistant" : "user";
              return { role, content: (m.message_content || "").slice(0, 4096) };
            });
        if (history.length > 0) {
          const last = history[history.length - 1];
          if (last.role === "user" && normalizeForCompare(last.content) === normalizeForCompare(combinedMessage)) {
            history = history.slice(0, -1);
          }
        }

        // ── Detectar intent antes de decidir se limpa histórico ──
        let intent = detectIntent(combinedMessage);

        // Declarar override de intent antes dos checks que podem setá-lo
        let openOrderHint = "";
        let smartIntentOverride: SmartIntent | undefined;

        // ── FIX: Mensagens curtas de confirmação ("pronto", "feito") devem ser payment_proof
        // SOMENTE se o atendente acabou de pedir comprovante/pix no histórico ──
        const shortConfirmPattern = /^(pronto|feito|enviado|mandei|enviei|ja fiz|já fiz)\s*[!.]*\s*$/i;
        if (shortConfirmPattern.test(normalizeForCompare(combinedMessage)) && intent === "other") {
          const lastAssistant = [...history].reverse().find((h) => h.role === "assistant");
          const lastAssistantNorm = normalizeForCompare(lastAssistant?.content || "");
          if (lastAssistantNorm.includes("pix") || lastAssistantNorm.includes("comprovante") || lastAssistantNorm.includes("pagamento") || lastAssistantNorm.includes("transferi")) {
            intent = "payment_proof";
          }
          // Se não era sobre pagamento, mantém "other" — o LLM interpreta do contexto
        }

        // ── FIX: Respostas curtas ("sim", "não", "2kg", "chocolate", "ok") ficam com intent "other"
        // que carrega notas genéricas. Se o stage indica pedido em andamento, usar intent do
        // último fluxo para que o routeNotes busque as notas certas ──
        const prevStage = (sessionMemory.stage as string) || "start";
        const prevIntent = (sessionMemory.last_intent as string) || "";
        if (intent === "other" && combinedMessage.trim().length < 60 && prevStage !== "start") {
          // Mapear stage do pedido para smart intent adequado
          const stageToSmartIntent: Record<string, SmartIntent> = {
            collecting_items: "order_now",
            awaiting_order_type: "order_now",
            confirming_order: "order_now",
            awaiting_payment: "payment",
          };
          const contextIntent = stageToSmartIntent[prevStage];
          if (contextIntent && !smartIntentOverride) {
            smartIntentOverride = contextIntent;
            console.log(`evolution-webhook: short answer override → ${contextIntent} (stage=${prevStage})`);
          }
        }

        // ── MELHORIA: Verificar se é cliente retornando com pedido em aberto ──
        // A instrução de COMO agir vem do knowledge_base (Obsidian: fluxos/fluxo-cliente-retornando)
        // Aqui só passamos os DADOS dinâmicos do pedido aberto como contexto
        const isReturningCustomer = sessionExpired && history.length > 0;

        if (isReturningCustomer || (intent === "greeting" && history.length > 2)) {
          // Verificar pedidos abertos no banco
          const { hasOpenOrder, orderSummary } = await checkOpenOrders(supabase, normalizedPhone);

          // Override do intent para "returning_customer" → routeNotes vai buscar
          // as notas certas do Obsidian (fluxos/fluxo-cliente-retornando, tom-de-voz, etc.)
          smartIntentOverride = "returning_customer";

          if (hasOpenOrder) {
            // Dados dinâmicos do pedido — o knowledge_base define o comportamento,
            // aqui são só os dados reais do banco para o LLM contextualizar
            openOrderHint = `[DADOS_PEDIDO_ABERTO]
${orderSummary}
[/DADOS_PEDIDO_ABERTO]`;
          }

          // Se sessão expirou, limpar histórico antigo para não confundir o LLM
          if (sessionExpired) {
            console.log("evolution-webhook: limpando histórico antigo para cliente retornando", remoteJid);
            history = [];
          }
        }

        // ── Contexto enriquecido: limpo e focado ──
        // Usar combinedMessage (mensagens agrupadas pelo debounce) para capturar contexto completo
        const stage = deriveStage(sessionMemory, intent, combinedMessage);

        // Se o stage resetou para "start" a partir de um pedido, é cancel
        if (stage === "start" && prevStage !== "start" && !smartIntentOverride) {
          smartIntentOverride = "cancel";
        }
        const orderMemoryHint = buildOrderMemoryHint(history as { role: "user" | "assistant"; content: string }[], sessionMemory);
        const previousQuestionHint = buildPreviousQuestionHint(history as { role: "user" | "assistant"; content: string }[], combinedMessage);
        const nowSp = new Date().toLocaleString("pt-BR", { timeZone: "America/Sao_Paulo" });

        // Construir contexto ESTRUTURADO — cada seção claramente separada
        const contextParts: string[] = [];

        // 1. Horário (sempre útil para regras de prazo)
        contextParts.push(`[HORA_ATUAL: ${nowSp}]`);

        // 1.5. Cliente retornando com pedido aberto (PRIORIDADE ALTA)
        if (openOrderHint) {
          contextParts.push(openOrderHint);
        }

        // 2. Controle de fluxo (intent + stage)
        contextParts.push(buildControlHint(intent, stage, sessionMemory));

        // 3. Memória de pedido em andamento (crucial para não perder itens)
        if (orderMemoryHint) {
          contextParts.push(orderMemoryHint);
        }

        // 4. Continuidade: se a mensagem parece resposta a uma pergunta anterior
        if (previousQuestionHint) {
          contextParts.push(`[CONTINUIDADE]\n${previousQuestionHint}`);
        }

        // 5. Instrução de resposta
        contextParts.push(`[INSTRUÇÃO]\nResponda SOMENTE com a mensagem para o cliente. Use as informações acima para NÃO re-perguntar nada que já foi dito. Seja curta, direta e humana.`);

        // 6. Mensagem do cliente SEMPRE por último
        contextParts.push(`[MENSAGEM DO CLIENTE]\n${combinedMessage}`);

        const enrichedMessage = contextParts.join("\n\n");

        // Cálculo determinístico de preço de bolo — ENRIQUECE a mensagem (não substitui LLM)
        // O LLM precisa usar esse valor exato e continuar o fluxo da conversa
        const deterministicPriceReply = detectCakePriceIntent(combinedMessage, recipeRowsTyped as { name: string; whole_price?: number | null; sale_price?: number | null; slice_price?: number | null }[]);
        let priceHint = "";
        if (deterministicPriceReply) {
          priceHint = `\n\n[CÁLCULO_EXATO_BOLO]\n${deterministicPriceReply}\nUse ESTE VALOR EXATO na resposta. Continue o fluxo normalmente (pergunte tipo de pedido se não informou, etc.).\n[/CÁLCULO_EXATO_BOLO]`;
        }

        {
          // ── Sistema Modular: passar intent/stage/hasOrder para prompt focado ──
          const orderMem = extractOrderMemory(history as { role: "user" | "assistant"; content: string }[]);
          const hasOrderInProgress = orderMem.items.length > 0;
          reply = await runAtendente(
            supabase,
            enrichedMessage + priceHint,
            pushName || "Cliente",
            history as { role: "user" | "assistant"; content: string }[],
            { intent, stage, hasOrderInProgress },
            smartIntentOverride
          );
        }

        const { replyClean, pedidoJson, encomendaJson, quitarEncomendaJson, atualizarClienteJson, alertaEquipeText } = parseCreateBlocks(reply);
        const decorationText = extractDecorationRequestFromMessage(combinedMessage);
        const pedidoJsonWithDecoration = applyDecorationToPedidoPayload(pedidoJson, decorationText);
        const encomendaJsonWithDecoration = applyDecorationToEncomendaPayload(encomendaJson, decorationText);
        const guardedReplyClean = enforceReplyGuardrails(replyClean || reply, recipeNames, combinedMessage);

        // ===== MELHORIA 4: Processar ALERTA_EQUIPE =====
        if (alertaEquipeText && ownerPhonesList.length > 0) {
          const alertMsg = `⚠️ Alerta do atendente IA:\n${alertaEquipeText}\n\nCliente: ${pushName || "não identificado"} (${normalizedPhone})`;
          for (const ownerPhone of ownerPhonesList) {
            try {
              await sendEvolutionMessage(evo.baseUrl, evo.apiKey, evo.instance, ownerPhone, alertMsg);
            } catch (e) {
              console.error("ALERTA_EQUIPE send error:", (e as Error).message);
            }
          }
        }

        if (atualizarClienteJson) {
          const phoneVal = typeof atualizarClienteJson.phone === "string" ? normalizePhone(atualizarClienteJson.phone) : normalizedPhone;
          const parseBirthday = (v: unknown): string | null => {
            if (typeof v !== "string" || !v.trim()) return null;
            const s = v.trim();
            const iso = /^\d{4}-\d{2}-\d{2}$/.test(s) ? s : null;
            if (iso) return iso;
            const ddmmyy = s.match(/^(\d{1,2})[\/\-](\d{1,2})[\/\-](\d{4})$/) || s.match(/^(\d{1,2})[\/\-](\d{1,2})[\/\-](\d{2})$/);
            if (ddmmyy) {
              const day = ddmmyy[1].padStart(2, "0");
              const month = ddmmyy[2].padStart(2, "0");
              const year = ddmmyy[3].length === 4 ? ddmmyy[3] : "20" + ddmmyy[3];
              return `${year}-${month}-${day}`;
            }
            return null;
          };
          const birthdayVal = parseBirthday(atualizarClienteJson.birthday);
          const { data: cust } = await supabase.from("customers").select("id").eq("phone", phoneVal).limit(1).maybeSingle();
          if (cust?.id) {
            const updates: { name?: string; email?: string; address?: string; birthday?: string } = {};
            if (typeof atualizarClienteJson.name === "string" && atualizarClienteJson.name.trim()) updates.name = sanitizeName(atualizarClienteJson.name.trim());
            if (typeof atualizarClienteJson.email === "string" && atualizarClienteJson.email.trim()) updates.email = atualizarClienteJson.email.trim().slice(0, 255);
            if (typeof atualizarClienteJson.address === "string" && atualizarClienteJson.address.trim()) updates.address = atualizarClienteJson.address.trim().slice(0, 500);
            if (birthdayVal) updates.birthday = birthdayVal;
            if (Object.keys(updates).length > 0) {
              await supabase.from("customers").update(updates).eq("id", cust.id);
              console.log("evolution-webhook: cliente atualizado (cadastro)", cust.id);
            }
          } else {
            const name = typeof atualizarClienteJson.name === "string" ? sanitizeName(atualizarClienteJson.name.trim()) || "Cliente" : (pushName || "Cliente");
            await findOrCreateCustomer(supabase, phoneVal, name);
            const { data: cust2 } = await supabase.from("customers").select("id").eq("phone", normalizePhone(phoneVal)).limit(1).maybeSingle();
            if (cust2?.id) {
              const updates: { name?: string; email?: string; address?: string; birthday?: string } = {};
              if (typeof atualizarClienteJson.name === "string" && atualizarClienteJson.name.trim()) updates.name = sanitizeName(atualizarClienteJson.name.trim());
              if (typeof atualizarClienteJson.email === "string" && atualizarClienteJson.email.trim()) updates.email = atualizarClienteJson.email.trim().slice(0, 255);
              if (typeof atualizarClienteJson.address === "string" && atualizarClienteJson.address.trim()) updates.address = atualizarClienteJson.address.trim().slice(0, 500);
              if (birthdayVal) updates.birthday = birthdayVal;
              if (Object.keys(updates).length > 0) await supabase.from("customers").update(updates).eq("id", cust2.id);
              console.log("evolution-webhook: cliente criado/atualizado (cadastro)", cust2.id);
            }
          }
        }

        // ===== MELHORIA 6: Salvar payment_confirmation COM payload (sem criar pedido ainda) =====
        if (pedidoJsonWithDecoration) {
          try {
            await supabase.from("payment_confirmations").insert({
              customer_name: (pedidoJsonWithDecoration.customer_name as string) || pushName || "Cliente",
              customer_phone: normalizedPhone,
              remote_jid: remoteJid,
              description: JSON.stringify(pedidoJsonWithDecoration.items || []).slice(0, 500),
              type: "pedido",
              channel: "whatsapp",
              status: "pending",
              order_payload: pedidoJsonWithDecoration,
            } as Record<string, unknown>);
            console.log("evolution-webhook: comprovante de pedido salvo para aprovação manual");
          } catch (e) { console.error("payment_confirmation insert:", (e as Error).message); }
        }
        if (encomendaJsonWithDecoration) {
          try {
            await supabase.from("payment_confirmations").insert({
              customer_name: (encomendaJsonWithDecoration.customer_name as string) || pushName || "Cliente",
              customer_phone: normalizedPhone,
              remote_jid: remoteJid,
              description: (encomendaJsonWithDecoration.product_description as string) || "Encomenda",
              type: "encomenda",
              channel: "whatsapp",
              status: "pending",
              order_payload: encomendaJsonWithDecoration,
            } as Record<string, unknown>);
            console.log("evolution-webhook: comprovante de encomenda salvo para aprovação manual");
          } catch (e) { console.error("payment_confirmation insert:", (e as Error).message); }
        }
        if (quitarEncomendaJson) {
          const result = await settleEncomendaFromPayload(supabase, quitarEncomendaJson, normalizedPhone);
          if (result.ok) {
            console.log("evolution-webhook: encomenda quitada na plataforma", result.encomendaId);
          } else {
            console.error("evolution-webhook: falha ao quitar encomenda", result.error);
          }
        }
        reply = guardedReplyClean || replyClean || reply;
        reply = enforceOrderTypeQuestion(reply, intent, stage, combinedMessage);
        reply = enforceCakeContinuity(reply, combinedMessage, history as { role: "user" | "assistant"; content: string }[]);

        // ===== MELHORIA 1: Salvar sessão de conversa =====
        // Extrair e persistir dados confirmados do pedido para não depender apenas de regex no histórico
        const extractedOrder = extractOrderMemory(history as { role: "user" | "assistant"; content: string }[]);
        const clientTextForSession = (history as { role: "user" | "assistant"; content: string }[])
          .filter((h) => h.role === "user")
          .map((h) => h.content || "")
          .join("\n") + "\n" + combinedMessage;

        // Extrair peso, sabor, tipo com os mesmos regex do buildOrderMemoryHint
        const sessionWeights = [...clientTextForSession.matchAll(/(\d+)\s*kg/gi)].map((m) => `${m[1]}kg`);
        const sessionFlavors = [...clientTextForSession.matchAll(/(?:bolo\s+(?:de\s+)?|pode\s+ser\s+(?:de\s+)?|vai\s+ser\s+(?:de\s+)?|quero\s+(?:de\s+)?|o\s+de\s+)([a-záàâãéèêíïóôõúüç\s]+)/gi)]
          .map((m) => m[1].trim()).filter((f) => f.length > 2 && !f.match(/^\d/));
        const sessionOrderType = clientTextForSession.toLowerCase().includes("delivery") ? "delivery"
          : clientTextForSession.toLowerCase().includes("encomenda") ? "encomenda"
          : clientTextForSession.toLowerCase().includes("retirada") ? "retirada"
          : (sessionMemory.order_type as string) || "";

        const sessionUpdate: Record<string, unknown> = {
          memory: {
            last_message: combinedMessage.slice(0, 300),
            last_reply: reply.slice(0, 300),
            last_intent: intent,
            stage,
            // Dados persistidos do pedido — sobrevivem entre invocações
            confirmed_weight: sessionWeights.length > 0 ? sessionWeights[sessionWeights.length - 1] : (sessionMemory.confirmed_weight || ""),
            confirmed_flavor: sessionFlavors.length > 0 ? sessionFlavors[sessionFlavors.length - 1] : (sessionMemory.confirmed_flavor || ""),
            order_type: sessionOrderType || (sessionMemory.order_type || ""),
            order_items: extractedOrder.items.slice(-12),
            updated: new Date().toISOString(),
          },
          customer_name: pushName || (sessionRow as any)?.customer_name || null,
          updated_at: new Date().toISOString(),
        };
        if (sessionRow) {
          await supabase.from("sessions").update(sessionUpdate as any).eq("remote_jid", remoteJid);
        } else {
          try { await supabase.from("sessions").insert({ remote_jid: remoteJid, ...sessionUpdate } as Record<string, unknown>); } catch (_) {}
        }

        await supabase.from("crm_messages").insert({
          customer_id: customerId,
          message_type: "whatsapp_saida",
          message_content: reply,
          status: "enviada",
          sent_at: new Date().toISOString(),
        });
      }
    } catch (e) {
      console.error("evolution-webhook process error:", (e as Error).message);
      reply = FALLBACK_REPLY;
    }

    try {
      await sendEvolutionMessage(evo.baseUrl, evo.apiKey, evo.instance, normalizedPhone, reply);
    } catch (e) {
      console.error("evolution-webhook send error:", (e as Error).message);
      return new Response(
        JSON.stringify({ ok: false, error: "Send failed" }),
        { status: 200, headers: { ...corsHeaders, "Content-Type": "application/json" } }
      );
    }

    return new Response(JSON.stringify({ ok: true, isOwner }), {
      status: 200,
      headers: { ...corsHeaders, "Content-Type": "application/json" },
    });
  } catch (e) {
    console.error("evolution-webhook error:", (e as Error).message);
    return new Response(
      JSON.stringify({ ok: false, error: "Internal error" }),
      { status: 500, headers: { ...corsHeaders, "Content-Type": "application/json" } }
    );
  }
});

import type { SupabaseClient } from "https://esm.sh/@supabase/supabase-js@2";
import { sanitizeMessage, sanitizeHistory, MAX_MESSAGE_LENGTH } from "./security.ts";
import { buildAtendenteBasePrompt } from "./atendentePromptBase.ts";
import {
  buildModularAtendentePrompt,
  type PromptIntent,
  type PromptStage,
} from "./atendentePromptModules.ts";
import { fetchAndBuildRules } from "./fetchRules.ts";
import { buildDecisionContext, buildSmartPrompt, detectEntities } from "./decisionLayer.ts";
import type { Intent } from "./routeNotes.ts";
import type { RecipeInfo } from "./calculator.ts";

/** Timeout para chamada ao LLM (ms). */
const LLM_TIMEOUT_MS = 28000;

/** Resposta padrão quando a IA falha (assistente). */
const FALLBACK_ASSISTENTE = "No momento não consegui processar. Pode repetir em poucos segundos ou ver os dados direto no painel.";

/** Resposta padrão quando a IA falha (atendente). */
const FALLBACK_ATENDENTE = "Obrigado pela mensagem! Nossa equipe já foi avisada e em breve retorna. Qualquer dúvida, estamos à disposição.";

/** Link fixo do cardápio completo em PDF (Drive). */
const CARDAPIO_PDF_URL = "http://bit.ly/3OYW9Fw";

/**
 * Capacidades de dados que o agente pode usar.
 * - Usado pelo `agent-chat` (dono) e pelo `evolution-webhook` (quando falar com o dono).
 * - Para adicionar novas áreas (ex.: metas, financeiro), incluir aqui e tratar em `buildDataContext`.
 */
export const CAPABILITIES = [
  "reports",
  "sales",
  "stock",
  "employees",
  "clients",
  "demands",
  "offers",
  "crm_kanban",
] as const;

export async function buildDataContext(
  supabase: SupabaseClient,
  capabilities: readonly string[]
): Promise<Record<string, unknown>> {
  const now = new Date();
  const start30 = new Date(now);
  start30.setDate(start30.getDate() - 30);
  const start7 = new Date(now);
  start7.setDate(start7.getDate() - 7);
  const start7Str = start7.toISOString();
  const start30Str = start30.toISOString();
  const nowStr = now.toISOString();
  const ctx: Record<string, unknown> = {};

  if (capabilities.includes("reports") || capabilities.includes("sales")) {
    const [salesRes, prevRes] = await Promise.all([
      supabase.from("sales").select("total, payment_method, channel, sold_at").gte("sold_at", start30Str).lte("sold_at", nowStr),
      supabase.from("sales").select("total").gte("sold_at", new Date(start30.getTime() - 30 * 24 * 60 * 60 * 1000).toISOString()).lt("sold_at", start30Str),
    ]);
    const current = (salesRes.data || []) as { total: number; channel?: string; payment_method?: string }[];
    const prev = (prevRes.data || []) as { total: number }[];
    const currentTotal = current.reduce((s, x) => s + Number(x.total), 0);
    const prevTotal = prev.reduce((s, x) => s + Number(x.total), 0);
    const growth = prevTotal > 0 ? ((currentTotal - prevTotal) / prevTotal * 100) : 0;
    const byChannel: Record<string, number> = {};
    const byPayment: Record<string, number> = {};
    for (const s of current) {
      byChannel[s.channel || "outro"] = (byChannel[s.channel || "outro"] || 0) + Number(s.total);
      byPayment[s.payment_method || "outro"] = (byPayment[s.payment_method || "outro"] || 0) + Number(s.total);
    }
    ctx.sales = {
      last30Days: { total: currentTotal, count: current.length, growth, byChannel, byPayment },
      ticketMedio: current.length ? currentTotal / current.length : 0,
    };
  }

  if (capabilities.includes("stock")) {
    const [invRes, alertsRes] = await Promise.all([
      supabase.from("inventory").select("id, status, stock_grams, recipes(name)"),
      supabase.from("alerts").select("id, alert_type, message, resolved").eq("resolved", false),
    ]);
    const inv = (invRes.data || []) as { status: string }[];
    const byStatus = inv.reduce((acc: Record<string, number>, i) => {
      acc[i.status] = (acc[i.status] || 0) + 1;
      return acc;
    }, {});
    ctx.inventory = { byStatus, totalItems: inv.length, alerts: alertsRes.data || [] };
  }

  if (capabilities.includes("employees")) {
    const { data: roles } = await supabase.from("user_roles").select("user_id, role");
    const userIds = [...new Set((roles || []).map((r: { user_id: string }) => r.user_id))];
    const { data: profs } = userIds.length
      ? await supabase.from("profiles").select("user_id, name, phone").in("user_id", userIds)
      : { data: [] };
    const rolesList = (roles || []) as { user_id: string; role: string }[];
    ctx.employees = {
      count: userIds.length,
      list: ((profs as { user_id: string; name: string }[]) || []).map((p) => ({
        name: p.name,
        role: rolesList.find((r) => r.user_id === p.user_id)?.role,
      })),
    };
  }

  if (capabilities.includes("clients") || capabilities.includes("crm_kanban")) {
    const [custRes, leadsRes] = await Promise.all([
      supabase.from("customers").select("id, name, phone, status, total_spent, last_purchase_at").order("last_purchase_at", { ascending: false }).limit(50),
      supabase.from("social_leads").select("id, name, phone, status, source, potential_value, follow_up_date").order("created_at", { ascending: false }).limit(50),
    ]);
    const customers = (custRes.data || []) as Record<string, unknown>[];
    const leads = (leadsRes.data || []) as { status: string }[];
    const leadsByStatus = leads.reduce((acc: Record<string, number>, l) => {
      acc[l.status] = (acc[l.status] || 0) + 1;
      return acc;
    }, {});
    ctx.customers = { count: customers.length, recent: customers.slice(0, 15) };
    ctx.leads = { count: leads.length, byStatus: leadsByStatus, recent: leads.slice(0, 15) };
  }

  if (capabilities.includes("demands")) {
    const { data: orders } = await supabase
      .from("orders")
      .select("id, status, customer_phone, customer_name, created_at")
      .gte("created_at", start7Str)
      .order("created_at", { ascending: false })
      .limit(30);
    ctx.orders = { last7Days: orders || [], count: (orders || []).length };
  }

  if (capabilities.includes("reports")) {
    const { data: aiReports } = await supabase.from("ai_reports").select("summary, content, period_days, created_at").order("created_at", { ascending: false }).limit(5);
    ctx.ai_reports = aiReports || [];
  }

  if (capabilities.includes("offers")) {
    const { data: promos } = await supabase.from("auto_promotions").select("id, discount_percent, promo_price, status, expires_at").eq("status", "ativa").limit(20);
    ctx.promotions = promos || [];
  }

  return ctx;
}

export function buildAssistentePrompt(
  dataContext: Record<string, unknown>,
  customInstructions?: string | null
): string {
  const ctxStr = JSON.stringify(dataContext, null, 2);
  const truncated = ctxStr.length > 12000 ? ctxStr.slice(0, 11900) + "\n...(dados truncados)" : ctxStr;
  const safeCustom = (customInstructions || "").trim().slice(0, 2000).replace(/\n/g, " ");
  const customBlock = safeCustom
    ? `\n\nINSTRUÇÕES DO PROPRIETÁRIO (siga também aqui):\n${safeCustom}\n`
    : "";
  return `Você é o assistente pessoal do dono do Café Café Confeitaria — um parceiro de confiança que conhece o negócio e fala como pessoa real. Você atua como assistente de gestão quando o dono pergunta por vendas, pedidos, estoque ou relatórios.${customBlock}

PERSONALIDADE E TOM:
- Fale em português brasileiro, de forma natural e calorosa, como numa conversa de WhatsApp com o dono.
- Com o dono você pode ser mais objetivo e usar listas quando for relatório ou muitos números.
- Use "você" e "a gente"; evite linguagem corporativa ou robótica.
- Quando fizer sentido, faça uma pergunta de follow-up ou um comentário breve.
- Se os dados forem positivos, reconheça de forma genuína; se houver algo para atenção, seja direto mas empático.

FUNÇÕES PARA O PROPRIETÁRIO:
- Relatórios: se o dono pedir relatório e não indicar período, use últimos 7 dias. Informe: total vendido, número de pedidos, ticket médio, produtos mais vendidos.
- Estoque: quando pedir estoque, mostrar produtos com estoque baixo e estoque crítico.
- Alertas: você pode avisar o dono quando houver estoque baixo, produto acabando, aumento de vendas ou produto com baixa saída (ex.: "O bolo de prestígio está quase acabando no estoque.").
- Sugestões: pode sugerir produzir mais de um produto, fazer promoção ou retirar produto com pouca saída — sempre como sugestão.
- Análise de vendas: organize de forma clara (total vendido, pedidos, ticket médio; produtos mais vendidos; produtos com pouca saída). Pode apontar tendências (ex.: "O bolo de brigadeiro está vendendo muito mais que os outros sabores.").

REGRAS DE DADOS:
- Use APENAS os dados fornecidos abaixo. Nunca invente números, nomes ou fatos.
- Se não houver dado para o que foi perguntado, diga isso de forma natural.

PDF E DOCUMENTOS:
- A mensagem do dono pode incluir "[Conteúdo do PDF anexado]" com texto extraído de um PDF.
- Analise esse conteúdo quando o dono pedir para registrar algo, conferir comprovante ou usar informações do documento.
- Resuma, extraia dados relevantes (valores, datas, nomes) e responda com base no que está no PDF quando fizer sentido.

DADOS ATUAIS DA PLATAFORMA (use só isso para responder):
${truncated}`;
}

function getPaymentInfoFromSettings(settings: { key: string; value: string }[]): string {
  const map = new Map(settings.map((s) => [s.key, s.value]));
  const pix = (map.get("payment_pix_key") || "").trim();
  const instructions = (map.get("payment_instructions") || "").trim();
  const parts: string[] = [];
  if (pix) parts.push(`Chave PIX para pagamento: ${pix}`);
  if (instructions) parts.push(instructions);
  if (parts.length === 0) return "Formas de pagamento: aceitamos PIX, cartão, dinheiro. Detalhes serão passados pela equipe no momento do pedido.";
  return parts.join(". ");
}

export function buildAtendentePrompt(
  contactName: string,
  promoSummary: string,
  paymentInfo: string,
  customInstructions?: string | null,
  cardapioAcai?: string | null,
  cardapioProdutos?: string | null,
  cardapioProdutosDetalhado?: string | null
): string {
  const safeName = contactName.slice(0, 100).replace(/\n/g, " ");
  const safePromo = promoSummary.slice(0, 500).replace(/\n/g, " ");
  const safePayment = paymentInfo.slice(0, 800).replace(/\n/g, " ");
  // Mantém quase todo o texto das instruções do proprietário (até 6000 caracteres) e preserva quebras de linha
  const safeCustom = (customInstructions || "").trim().slice(0, 6000);
  const customBlock = safeCustom
    ? `\n\nINSTRUÇÕES DO PROPRIETÁRIO (PRIORIDADE MÁXIMA):\n${safeCustom}\n`
    : "";
  const acaiBlock = (cardapioAcai || "").trim()
    ? `

AÇAÍ (MONTAR) E COMPLEMENTOS:
${cardapioAcai}
- Pergunte quais complementos o cliente deseja e anote na observação do pedido.
- Para entrega, confirme os complementos antes de fechar.`
    : "";

  const cardapioDetalhado = (cardapioProdutosDetalhado || "").trim();
  const cardapioBlock = cardapioDetalhado
    ? `

CARDÁPIO E PREÇOS (FONTE DE VERDADE PARA VALORES):
${cardapioDetalhado}

REGRA DE BOLOS POR KG:
- valor_total = preço_por_kg × quantidade_em_kg. NUNCA informe o preço de 1kg para 2kg ou mais.
- Encomenda acima de R$300: entrada de 50%. Até R$300: pagamento integral.
`
    : "";

  const createBlock = (cardapioProdutos || "").trim()
    ? `

REGISTRO AUTOMÁTICO NA PLATAFORMA:
- Quando o cliente finalizar o pedido E enviar comprovante, inclua no FINAL da resposta o bloco correspondente (o cliente não vê).

1) PEDIDO NORMAL: [CRIAR_PEDIDO] com JSON. Nomes exatos: ${(cardapioProdutos ?? "").replace(/\n/g, ", ")}.
Exemplo: [CRIAR_PEDIDO]{"customer_name":"Nome","customer_phone":"5511999999999","channel":"delivery","order_number":"","table_number":"","payment_method":"pix","items":[{"recipe_name":"Abacaxi com Creme","quantity":1,"unit_type":"whole","notes":""}]}[/CRIAR_PEDIDO]
- Se o cliente pedir decoração, escreva no campo "notes" do item a descrição EXATA que o cliente falou.

2) ENCOMENDA acima de R$300 (50% entrada): [CRIAR_ENCOMENDA] com paid_50_percent=true.
Exemplo: [CRIAR_ENCOMENDA]{"customer_name":"Nome","customer_phone":"5511999999999","product_description":"Bolo 1kg","quantity":1,"total_value":320,"address":"Rua X 123","payment_method":"pix","paid_50_percent":true,"observations":"","delivery_date":"2025-03-15","delivery_time_slot":"14h às 18h"}[/CRIAR_ENCOMENDA]
- Se houver decoração, coloque a descrição EXATA do cliente no campo "observations".

3) QUITAR ENCOMENDA (restante dos 50%): [QUITAR_ENCOMENDA] com customer_phone, payment_value, payment_date.
Exemplo: [QUITAR_ENCOMENDA]{"customer_phone":"5511999999999","payment_value":60,"payment_date":"2025-03-20"}[/QUITAR_ENCOMENDA]

4) CADASTRO DO CLIENTE: [ATUALIZAR_CLIENTE] quando tiver nome, telefone, email, endereço e aniversário.
Formato: [ATUALIZAR_CLIENTE]{"name":"Nome","phone":"5511999999999","email":"email@exemplo.com","address":"Rua, número, bairro, cidade","birthday":"1990-05-15"}[/ATUALIZAR_CLIENTE]

5) DÚVIDA / ACIONAR EQUIPE: [ALERTA_EQUIPE]Texto curto explicando a dúvida.[/ALERTA_EQUIPE]`
    : "";

  const basePrompt = buildAtendenteBasePrompt();
  return `REGRA #1 — SÓ PRODUTOS DO CARDÁPIO:
Você SÓ pode citar, recomendar ou mencionar produtos que estejam na lista "CARDÁPIO E PREÇOS" deste prompt. Se não está na lista, NÃO EXISTE. Nunca invente sabores.

REGRA #2 — CONVERSA CONTÍNUA:
Leia o histórico inteiro antes de responder. Mantenha coerência. Não repita perguntas já respondidas.

${basePrompt}
${customBlock}
${acaiBlock}
${cardapioBlock}
${createBlock}

INFORMAÇÕES DO CONTATO:
- Nome: ${safeName || "não informado"}
- Promoções: ${safePromo || "nenhuma"}
- Pagamento: ${safePayment}

CARDÁPIO COMPLETO EM PDF: ${CARDAPIO_PDF_URL}
- Envie o link quando pedirem o cardápio completo. Se perguntarem preço específico, informe o valor direto.
`;
}

export type LlmConfig = { apiKey: string; baseUrl: string; model: string };

export async function getLlmConfig(supabase: SupabaseClient): Promise<LlmConfig | null> {
  const lovableKey = Deno.env.get("LOVABLE_API_KEY") || "";
  const { data: rows } = await supabase.from("crm_settings").select("key, value").in("key", ["agent_api_key", "agent_api_base", "agent_model"]);
  const map = new Map((rows || []).map((r: { key: string; value: string }) => [r.key, r.value]));
  const agentKey = (map.get("agent_api_key") || "").trim();
  if (agentKey) {
    const base = (map.get("agent_api_base") || "https://api.openai.com/v1").trim().replace(/\/$/, "");
    const model = (map.get("agent_model") || "gpt-4o").trim() || "gpt-4o";
    return { apiKey: agentKey, baseUrl: base, model };
  }
  if (lovableKey) {
    return {
      apiKey: lovableKey,
      baseUrl: "https://ai.gateway.lovable.dev/v1",
      model: "gpt-4o",
    };
  }
  return null;
}

export async function callLlm(
  config: LlmConfig,
  systemPrompt: string,
  userMessage: string,
  history: { role: "user" | "assistant"; content: string }[],
  signal?: AbortSignal | null
): Promise<string> {
  const safeMessage = sanitizeMessage(userMessage).slice(0, MAX_MESSAGE_LENGTH);
  // Enviar histórico completo ao LLM (até 20 mensagens, que é o que vem do banco)
  // Mensagens muito grandes são truncadas para economizar tokens
  const recentHistory = history.slice(-20).map((m) => ({
    role: m.role as "user" | "assistant",
    content: m.content.slice(0, 2000),
  }));
  const messages: { role: "system" | "user" | "assistant"; content: string }[] = [
    { role: "system", content: systemPrompt },
    ...recentHistory,
    { role: "user", content: safeMessage },
  ];
  const url = `${config.baseUrl}/chat/completions`;
  const candidates = new Set<string>([config.model]);
  if (config.baseUrl.includes("lovable.dev")) {
    // Gateway pode exigir provider/model. Mantemos fallback para evitar indisponibilidade total.
    candidates.add("openai/gpt-4o");
    candidates.add("gpt-4o");
    candidates.add("google/gemini-3-flash-preview");
  }

  let lastErr = "";
  for (const model of candidates) {
    const res = await fetch(url, {
      method: "POST",
      signal,
      headers: {
        Authorization: `Bearer ${config.apiKey}`,
        "Content-Type": "application/json",
      },
      body: JSON.stringify({ model, messages, temperature: 0.05, max_tokens: 1500 }),
    });
    if (!res.ok) {
      const text = await res.text().catch(() => "");
      lastErr = `model=${model} status=${res.status} ${text.slice(0, 200)}`;
      continue;
    }
    const data = await res.json();
    const content = data.choices?.[0]?.message?.content;
    if (typeof content !== "string" || !content.trim()) {
      lastErr = `model=${model} resposta vazia`;
      continue;
    }
    return content.slice(0, 4096).trim();
  }

  throw new Error(`LLM error: ${lastErr || "sem resposta válida dos modelos"}`);
}

export async function runAssistente(
  supabase: SupabaseClient,
  message: string,
  history: { role: "user" | "assistant"; content: string }[]
): Promise<string> {
  const safeHistory = sanitizeHistory(history);
  const safeMessage = sanitizeMessage(message);
  if (!safeMessage) return FALLBACK_ASSISTENTE;
  const controller = new AbortController();
  const timeoutId = setTimeout(() => controller.abort(), LLM_TIMEOUT_MS);
  try {
    const [dataContext, settingsRes] = await Promise.all([
      buildDataContext(supabase, CAPABILITIES),
      supabase.from("crm_settings").select("key, value").in("key", ["atendente_instructions"]),
    ]);
    const instructionsRow = (settingsRes.data || []).find((s: { key: string; value: string }) => s.key === "atendente_instructions");
    const customInstructions = instructionsRow?.value ?? null;
    const systemPrompt = buildAssistentePrompt(dataContext, customInstructions);
    const config = await getLlmConfig(supabase);
    if (config) {
      const reply = await callLlm(config, systemPrompt, safeMessage, safeHistory, controller.signal);
      return reply || FALLBACK_ASSISTENTE;
    }
    return `Dados disponíveis: ${JSON.stringify(dataContext).slice(0, 1200)}. Configure a API de IA em CRM > Configurações para respostas completas.`;
  } catch (e) {
    if ((e as Error).name === "AbortError") return FALLBACK_ASSISTENTE;
    console.error("runAssistente error:", (e as Error).message);
    return FALLBACK_ASSISTENTE;
  } finally {
    clearTimeout(timeoutId);
  }
}

/**
 * Mapeia o intent legado (PromptIntent) para o novo sistema (Intent do routeNotes).
 * Permite compatibilidade com o webhook existente enquanto migra para o novo.
 */
function mapLegacyIntent(legacyIntent?: PromptIntent): Intent {
  if (!legacyIntent) return "unknown";
  const map: Record<string, Intent> = {
    greeting: "greeting",
    start_order: "order_now",
    ask_price: "pricing",
    ask_recommendation: "pricing",
    delivery_urgency: "delivery",
    payment_proof: "payment",
    other: "unknown",
  };
  return map[legacyIntent] || "unknown";
}

export async function runAtendente(
  supabase: SupabaseClient,
  message: string,
  contactName: string,
  history: { role: "user" | "assistant"; content: string }[],
  /** Novos parâmetros opcionais para o sistema modular */
  modularOpts?: {
    intent: PromptIntent;
    stage: PromptStage;
    hasOrderInProgress: boolean;
  },
  /** Nova arquitetura: intent do routeNotes (mais granular) */
  smartIntent?: Intent
): Promise<string> {
  const safeMessage = sanitizeMessage(message);
  if (!safeMessage) return FALLBACK_ATENDENTE;
  const safeHistory = sanitizeHistory(history);
  const controller = new AbortController();
  const timeoutId = setTimeout(() => controller.abort(), LLM_TIMEOUT_MS);
  try {
    const [promosRes, settingsRes, acaiRes, allRecipesRes, deliveryZonesRes] = await Promise.all([
      supabase.from("auto_promotions").select("discount_percent, promo_price, status").eq("status", "ativa").limit(5),
      supabase.from("crm_settings").select("key, value").in("key", ["payment_pix_key", "payment_instructions", "atendente_instructions"]),
      supabase.from("recipes").select("id, name, sale_price, slice_price, complementos").eq("active", true).eq("category", "acai"),
      supabase.from("recipes").select("id, name, sale_price, slice_price, whole_price").eq("active", true).order("name"),
      supabase.from("delivery_zones_disponibilidade").select("bairro, cidade, taxa, taxa_max, distancia_km, max_pedidos_dia, pedidos_hoje, vagas_restantes, disponivel").order("bairro").catch(() => ({ data: [] })),
    ]);
    const promos = (promosRes.data || []) as { discount_percent?: number; promo_price?: number }[];
    const promoSummary = promos.length
      ? promos.map((p) => `${p.discount_percent ?? 0}% off ou R$ ${p.promo_price ?? "?"}`).join("; ")
      : "nenhuma oferta ativa no momento";
    const settings = (settingsRes.data || []) as { key: string; value: string }[];
    const paymentInfo = getPaymentInfoFromSettings(settings);
    const customInstructions = settings.find((s) => s.key === "atendente_instructions")?.value ?? null;
    const acaiRecipes = (acaiRes.data || []) as { name: string; sale_price?: number; slice_price?: number; complementos?: string[] | null }[];
    const defaultComplements = ["Morango", "Banana", "Leite condensado", "Leite ninho", "Granola"];
    let cardapioAcai = "";
    if (acaiRecipes.length > 0) {
      const lines = acaiRecipes.map((r) => {
        const price = Number(r.slice_price ?? r.sale_price ?? 0);
        const comps = Array.isArray(r.complementos) && r.complementos.length > 0 ? r.complementos : defaultComplements;
        return `${r.name}: R$ ${price.toFixed(2)}. Complementos disponíveis: ${comps.join(", ")}.`;
      });
      cardapioAcai = lines.join("\n");
    }
    const allRecipes = (allRecipesRes.data || []) as { id: string; name: string; sale_price?: number | null; slice_price?: number | null; whole_price?: number | null }[];
    const cardapioProdutos = allRecipes.map((r) => r.name).join("\n");
    let cardapioProdutosDetalhado = allRecipes
      .map((r) => {
        const nome = r.name;
        const inteiro = r.whole_price != null ? `inteiro: R$ ${Number(r.whole_price).toFixed(2)}` : "";
        const fatia = r.slice_price != null ? `fatia: R$ ${Number(r.slice_price).toFixed(2)}` : "";
        const unidade = r.sale_price != null ? `unidade: R$ ${Number(r.sale_price).toFixed(2)}` : "";
        const partes = [inteiro, fatia, unidade].filter(Boolean).join(" | ");
        return partes ? `- ${nome} – ${partes}` : `- ${nome}`;
      })
      .join("\n");
    // Truncar cardápio se ultrapassar 4000 caracteres para economizar tokens
    if (cardapioProdutosDetalhado.length > 4000) {
      cardapioProdutosDetalhado = cardapioProdutosDetalhado.slice(0, 3950) + "\n...(cardápio truncado)";
    }

    // ── Montar tabela de zonas de delivery com disponibilidade ──
    interface DeliveryZoneDisp {
      bairro: string; cidade: string; taxa: number; taxa_max?: number | null;
      distancia_km?: number | null; max_pedidos_dia?: number;
      pedidos_hoje?: number; vagas_restantes?: number; disponivel?: boolean;
    }
    const deliveryZones = ((deliveryZonesRes as any)?.data || []) as DeliveryZoneDisp[];
    let deliveryZonesText = "";
    if (deliveryZones.length > 0) {
      const lines = deliveryZones.map((z) => {
        const taxaMin = Number(z.taxa).toFixed(2);
        const taxaStr = z.taxa_max ? `R$ ${taxaMin} a R$ ${Number(z.taxa_max).toFixed(2)}` : `R$ ${taxaMin}`;
        const dist = z.distancia_km != null ? `${z.distancia_km}km` : "";
        const limite = z.max_pedidos_dia ?? 20;
        const vagas = z.vagas_restantes ?? limite;
        const status = vagas <= 0 ? " ⛔ ESGOTADO HOJE" : vagas <= 3 ? ` ⚠️ ${vagas} vagas` : "";
        return `- ${z.bairro} (${z.cidade}): ${taxaStr} | ${dist} | máx ${limite}/dia${status}`;
      });
      deliveryZonesText = lines.join("\n");
    }

    // ════════════════════════════════════════════════════════════════
    // NOVA ARQUITETURA v2: routeNotes + decisionLayer + calculator
    //
    //   Mensagem → detectEntities → routeNotes → fetchNotas → preCalcular → LLM
    //
    //   Obsidian = memória e regras
    //   Calculator = cálculos exatos (FORA da LLM)
    //   LLM = raciocínio + conversa + condução
    // ════════════════════════════════════════════════════════════════
    let systemPrompt: string;

    // Determinar o intent granular (novo routeNotes)
    const effectiveIntent: Intent = smartIntent || mapLegacyIntent(modularOpts?.intent);

    try {
      // 1. Detectar entidades na mensagem
      const entities = detectEntities(safeMessage);

      // 2. Camada de decisão: rotear → buscar notas → pré-calcular
      const decisionCtx = await buildDecisionContext(
        supabase,
        safeMessage,
        effectiveIntent,
        entities,
        contactName,
        paymentInfo,
        (customInstructions || "").trim().slice(0, 6000),
        promoSummary,
        (cardapioAcai || "").trim(),
        (cardapioProdutosDetalhado || "").trim(),
        (cardapioProdutos || "").replace(/\n/g, ", "),
        deliveryZonesText,
        allRecipes as RecipeInfo[]
      );

      // 3. SEMPRE usar buildSmartPrompt (vault-based)
      // Mesmo se vault estiver vazio, o smartPrompt é enxuto e correto
      systemPrompt = buildSmartPrompt(decisionCtx);

      // Se vault estava vazio, logar para debug (mas NÃO usar fallback pesado)
      if (!decisionCtx.notasRelevantes) {
        console.warn("knowledge_base retornou vazio — usando smartPrompt mínimo (sem fallback hardcoded)");
      }
    } catch (e) {
      console.error("decisionLayer falhou:", (e as Error).message);
      // Fallback MÍNIMO — nunca mais usar buildModularAtendentePrompt pesado
      systemPrompt = buildModularAtendentePrompt({
        intent: modularOpts?.intent || "other",
        stage: modularOpts?.stage || "start",
        hasOrderInProgress: modularOpts?.hasOrderInProgress || false,
        contactName, promoSummary, paymentInfo, customInstructions,
        cardapioAcai: cardapioAcai || null,
        cardapioProdutos: cardapioProdutos || null,
        cardapioProdutosDetalhado: cardapioProdutosDetalhado || null,
        deliveryZonesText: deliveryZonesText || null,
      });
    }

    const config = await getLlmConfig(supabase);
    if (config) {
      const reply = await callLlm(config, systemPrompt, safeMessage, safeHistory, controller.signal);
      return reply || FALLBACK_ATENDENTE;
    }
    return "Olá! Obrigado pelo contato. Em breve nossa equipe retorna. Qual seu nome?";
  } catch (e) {
    if ((e as Error).name === "AbortError") return FALLBACK_ATENDENTE;
    console.error("runAtendente error:", (e as Error).message);
    return FALLBACK_ATENDENTE;
  } finally {
    clearTimeout(timeoutId);
  }
}

/**
 * atendentePromptModules.ts — Fallback MÍNIMO.
 *
 * IMPORTANTE: Todo conhecimento de atendimento vem do knowledge_base (Vault).
 * Este arquivo existe APENAS como fallback de emergência caso o vault esteja vazio.
 * Ele NÃO contém regras de negócio, cardápio, ou instruções detalhadas.
 * A LLM deve receber suas instruções via buildSmartPrompt (decisionLayer.ts).
 */

// Tipos mantidos para compatibilidade
export type PromptIntent =
  | "greeting"
  | "ask_price"
  | "ask_recommendation"
  | "start_order"
  | "delivery_urgency"
  | "payment_proof"
  | "other";

export type PromptStage =
  | "start"
  | "awaiting_order_type"
  | "collecting_items"
  | "confirming_order"
  | "awaiting_payment"
  | "post_payment";

export interface ModularPromptOptions {
  intent: PromptIntent;
  stage: PromptStage;
  hasOrderInProgress: boolean;
  contactName?: string;
  promoSummary?: string;
  paymentInfo?: string;
  customInstructions?: string;
  cardapioAcai?: string | null;
  cardapioProdutos?: string | null;
  cardapioProdutosDetalhado?: string | null;
