}

/**
 * Fallback MÍNIMO — usado APENAS quando o knowledge_base está vazio.
 * Contém SOMENTE identidade + estilo + regras invioláveis básicas.
 * NÃO contém cardápio, fluxos, regras de produto, ou instruções detalhadas.
 */
export function buildModularAtendentePrompt(opts: ModularPromptOptions): string {
  const safeName = (opts.contactName || "").trim();
  const safePayment = (opts.paymentInfo || "Aceitamos PIX, cartão e dinheiro").trim();
  const safePromo = (opts.promoSummary || "").trim();

  const parts: string[] = [];

  // 1. Identidade mínima + estilo (SEM regras de negócio detalhadas)
  parts.push(`Você é a atendente virtual da Café Café Confeitaria, Osasco-SP.
Atende clientes pelo WhatsApp de forma humana, acolhedora e direta.

ESTILO:
- Fale como brasileira de verdade: "você", "a gente", "tá bom", "certinho"
- Respostas CURTAS (máximo 2-3 linhas). Estilo WhatsApp, não email.
- Quando souber o nome: "Oi, [Nome]!"
- Emoji máximo 1 por mensagem, e só quando natural
- NUNCA use linguagem formal/corporativa
- NUNCA liste todos os produtos/sabores de uma vez
- NUNCA misture assuntos (se perguntou de bolo, fale só de bolo)

CONDUÇÃO:
- Uma pergunta de cada vez
- Novo atendimento → sempre pergunte: "É delivery, retirada ou encomenda?"
- Nunca antecipe informações que não foram pedidas
- Use CÁLCULOS PRÉ-FEITOS quando disponíveis — são exatos

REGRAS INVIOLÁVEIS:
- Só cite produtos que estejam no CARDÁPIO fornecido
- Nunca invente sabores, preços ou produtos
- Se não souber: "Vou verificar com a equipe!"
- Leia o histórico inteiro — nunca repita perguntas já respondidas`);

  // 2. Instruções do proprietário (se houver)
  if (opts.customInstructions) {
    parts.push(`\n═══ INSTRUÇÕES DO PROPRIETÁRIO ═══\n${opts.customInstructions}`);
  }

  // 3. Cardápio (fonte de verdade) — só se disponível
  const cardapio = (opts.cardapioProdutosDetalhado || "").trim();
  if (cardapio) {
    parts.push(`\n═══ CARDÁPIO E PREÇOS ═══\n${cardapio}\n⚠️ Se NÃO está aqui, NÃO EXISTE.`);
  }

  // 4. Açaí (quando disponível)
  const acai = (opts.cardapioAcai || "").trim();
  if (acai) {
    parts.push(`\n═══ AÇAÍ ═══\n${acai}`);
  }

  // 5. Zonas de delivery (quando disponível)
  const delivery = (opts.deliveryZonesText || "").trim();
  if (delivery) {
    parts.push(`\n═══ TAXAS DE ENTREGA ═══\n${delivery}`);
  }

  // 6. Dados do cliente
  parts.push(`\n═══ DADOS DO CLIENTE ═══
Nome: ${safeName || "não informado"}
Promoções: ${safePromo || "nenhuma"}
Pagamento: ${safePayment}`);

  // 7. Lembrete final
  parts.push(`\nRESPONDA SOMENTE COM A MENSAGEM PARA O CLIENTE. Curta, direta, humana.`);

  return parts.join("\n");
}

// Exports mantidos para compatibilidade (funções vazias)
export function moduleCore(): string { return ""; }
export function moduleAntiAlucinacao(): string { return ""; }

/**
 * calculator.ts — Calculadora de pedidos FORA da LLM.
 *
 * A LLM NÃO faz contas sozinha. Quem calcula é esta camada.
 * A LLM recebe os valores já calculados e só apresenta ao cliente.
 *
 * Funções:
 * - calcularBolo(sabor, peso, recipes) → valor
 * - calcularBoloMeioAMeio(sabor1, sabor2, peso, recipes) → valor
 * - calcularSalgados(quantidade) → valor
 * - calcularTotal(itens, taxa?, decoracao?) → total
 * - calcularEntrada(total) → { precisaEntrada, valorEntrada }
 * - validarQuantidadeSalgados(quantidade) → { valido, sugestao }
 * - dividirBoloGrande(pesoTotal) → formas[]
 */

// ── Tipos ──

export interface RecipeInfo {
  name: string;
  sale_price?: number | null;  // preço por kg
  slice_price?: number | null;  // preço fatia
  whole_price?: number | null;  // preço inteiro
}

export interface ItemCalculado {
  descricao: string;
  quantidade: number;
  precoUnitario: number;
  subtotal: number;
  detalhes?: string;
}

export interface ResultadoCalculo {
  itens: ItemCalculado[];
  subtotal: number;
  taxaEntrega: number;
  decoracao: number;
  total: number;
  precisaEntrada: boolean;
  valorEntrada: number;
  resumoTexto: string;
}

// ── Constantes ──

const PRECO_FATIA = 25;
const PRECO_CENTO_SALGADOS = 175;
const MIN_SALGADOS_POR_SABOR = 25;
const DECORACAO_VALOR = 30;
const LIMITE_FORMA_KG = 4;
const LIMIAR_ENTRADA = 300;
const MINIMO_DELIVERY = 50;

// ── Funções de cálculo ──

/**
 * Encontra o preço por kg de um sabor no cardápio.
 * Retorna null se não encontrar.
 */
export function buscarPrecoKg(sabor: string, recipes: RecipeInfo[]): number | null {
  const normalizado = sabor.toLowerCase().trim();
  const recipe = recipes.find(
    (r) => r.name.toLowerCase().trim() === normalizado
  );
  if (!recipe) return null;
  // sale_price = preço por kg para bolos
  return recipe.sale_price != null ? Number(recipe.sale_price) : null;
}

/**
 * Calcula o preço de um bolo por kg.
 */
export function calcularBolo(
  sabor: string,
  pesoKg: number,
  recipes: RecipeInfo[]
): { valor: number; precoKg: number } | null {
  const precoKg = buscarPrecoKg(sabor, recipes);
  if (precoKg == null) return null;
  return {
    valor: precoKg * pesoKg,
    precoKg,
  };
}

/**
 * Calcula bolo meio a meio.
 * Usa o MAIOR preço/kg entre os dois sabores × peso total.
 */
export function calcularBoloMeioAMeio(
  sabor1: string,
  sabor2: string,
  pesoKg: number,
  recipes: RecipeInfo[]
): { valor: number; precoKg: number; saborMaisCaro: string } | null {
  const preco1 = buscarPrecoKg(sabor1, recipes);
  const preco2 = buscarPrecoKg(sabor2, recipes);
  if (preco1 == null || preco2 == null) return null;

  const maiorPreco = Math.max(preco1, preco2);
  const saborMaisCaro = preco1 >= preco2 ? sabor1 : sabor2;

  return {
    valor: maiorPreco * pesoKg,
    precoKg: maiorPreco,
    saborMaisCaro,
  };
}

/**
 * Calcula mini salgados.
 */
export function calcularSalgados(quantidade: number): {
  valor: number;
  precoUnitario: number;
} {
  return {
    valor: (quantidade / 100) * PRECO_CENTO_SALGADOS,
    precoUnitario: PRECO_CENTO_SALGADOS / 100,
  };
}

/**
 * Valida se a quantidade de salgados é múltiplo de 25.
 * Se não for, sugere os dois múltiplos mais próximos.
 */
export function validarQuantidadeSalgados(quantidade: number): {
  valido: boolean;
  sugestaoInferior: number;
  sugestaoSuperior: number;
} {
  const valido = quantidade % MIN_SALGADOS_POR_SABOR === 0 && quantidade >= MIN_SALGADOS_POR_SABOR;
  const inferior = Math.floor(quantidade / MIN_SALGADOS_POR_SABOR) * MIN_SALGADOS_POR_SABOR;
  const superior = Math.ceil(quantidade / MIN_SALGADOS_POR_SABOR) * MIN_SALGADOS_POR_SABOR;
  return {
    valido,
    sugestaoInferior: inferior < MIN_SALGADOS_POR_SABOR ? MIN_SALGADOS_POR_SABOR : inferior,
    sugestaoSuperior: superior < MIN_SALGADOS_POR_SABOR ? MIN_SALGADOS_POR_SABOR : superior,
  };
}

/**
 * Calcula fatias de bolo do dia.
 */
export function calcularFatias(quantidade: number): {
  valor: number;
  precoUnitario: number;
} {
  return {
    valor: quantidade * PRECO_FATIA,
    precoUnitario: PRECO_FATIA,
  };
}

/**
 * Divide um bolo grande em múltiplas formas.
 * Limite da forma: 4kg.
 */
export function dividirBoloGrande(pesoTotal: number): number[] {
  if (pesoTotal <= LIMITE_FORMA_KG) return [pesoTotal];

  const formas: number[] = [];
  let restante = pesoTotal;
  while (restante > 0) {
    if (restante > LIMITE_FORMA_KG) {
      formas.push(LIMITE_FORMA_KG);
      restante -= LIMITE_FORMA_KG;
    } else {
      formas.push(restante);
      restante = 0;
    }
  }
  return formas;
}

/**
 * Calcula se precisa de entrada de 50%.
 */
export function calcularEntrada(total: number): {
  precisaEntrada: boolean;
  valorEntrada: number;
  valorRestante: number;
} {
  const precisaEntrada = total > LIMIAR_ENTRADA;
  const valorEntrada = precisaEntrada ? Math.ceil(total / 2 * 100) / 100 : total;
  const valorRestante = precisaEntrada ? total - valorEntrada : 0;
  return { precisaEntrada, valorEntrada, valorRestante };
}

/**
 * Verifica se o total atinge o mínimo para delivery.
 */
export function verificarMinimoDelivery(subtotal: number): {
  atinge: boolean;
  falta: number;
} {
  return {
    atinge: subtotal >= MINIMO_DELIVERY,
    falta: subtotal < MINIMO_DELIVERY ? MINIMO_DELIVERY - subtotal : 0,
  };
}

/**
 * Calcula o total final de um pedido completo.
 */
export function calcularTotal(
  itens: ItemCalculado[],
  taxaEntrega: number = 0,
  temDecoracao: boolean = false
): ResultadoCalculo {
  const subtotal = itens.reduce((sum, item) => sum + item.subtotal, 0);
  const decoracao = temDecoracao ? DECORACAO_VALOR : 0;
  const total = subtotal + taxaEntrega + decoracao;
  const { precisaEntrada, valorEntrada } = calcularEntrada(total);

  // Montar resumo em texto para a LLM apresentar
  const linhas = itens.map(
    (item) =>
      `• ${item.descricao}: ${item.quantidade > 1 ? `${item.quantidade} × ` : ""}R$${item.precoUnitario.toFixed(2)} = R$${item.subtotal.toFixed(2)}${item.detalhes ? ` (${item.detalhes})` : ""}`
  );

  if (temDecoracao) {
    linhas.push(`• Decoração: +R$${DECORACAO_VALOR.toFixed(2)}`);
  }
  if (taxaEntrega > 0) {
    linhas.push(`• Taxa de entrega: R$${taxaEntrega.toFixed(2)}`);
  }
  linhas.push(`Total: R$${total.toFixed(2)}`);
  if (precisaEntrada) {
    linhas.push(`Entrada (50%): R$${valorEntrada.toFixed(2)}`);
  }

  return {
    itens,
    subtotal,
    taxaEntrega,
    decoracao,
    total,
    precisaEntrada,
    valorEntrada,
    resumoTexto: linhas.join("\n"),
  };
}

// ── Validação de horário ──

/**
 * Verifica se um horário de encomenda tem antecedência suficiente.
 */
export function validarAntecedenciaEncomenda(
  horaDesejada: Date,
  agora: Date = new Date()
): { valido: boolean; horasSugeridas: number; horarioMinimo: Date } {
  const diffMs = horaDesejada.getTime() - agora.getTime();
  const diffHoras = diffMs / (1000 * 60 * 60);
  const MINIMO_HORAS = 4;

  const horarioMinimo = new Date(agora.getTime() + MINIMO_HORAS * 60 * 60 * 1000);

  return {
    valido: diffHoras >= MINIMO_HORAS,
    horasSugeridas: MINIMO_HORAS,
    horarioMinimo,
  };
}

/**
 * Verifica se está dentro do horário de funcionamento.
 * Segunda a sábado, 7h30 às 19h30.
 */
export function verificarHorarioFuncionamento(
  data: Date = new Date()
): { aberto: boolean; mensagem: string } {
  const dia = data.getDay(); // 0=dom, 6=sab
  const hora = data.getHours();
  const minuto = data.getMinutes();
  const minutosTotal = hora * 60 + minuto;

  // Domingo
  if (dia === 0) {
    return {
      aberto: false,
      mensagem: "Domingo não abrimos. Posso agendar pro próximo dia útil a partir das 12h!",
    };
  }

  // Antes das 7:30 ou depois das 19:30
  if (minutosTotal < 7 * 60 + 30 || minutosTotal > 19 * 60 + 30) {
    return {
      aberto: false,
      mensagem: "Estamos fora do horário (7h30–19h30). Posso anotar seu pedido e agendar!",
    };
  }

  return { aberto: true, mensagem: "" };
}

/**
 * Verifica se o delivery está disponível no horário.
 * Delivery começa às 9h.
 */
export function verificarHorarioDelivery(
  data: Date = new Date()
): { disponivel: boolean; mensagem: string } {
  const hora = data.getHours();
  if (hora < 9) {
    return {
      disponivel: false,
      mensagem: "O delivery começa às 9h. Qual horário depois das 9h fica bom?",
    };
  }
  return { disponivel: true, mensagem: "" };
}

/**
 * decisionLayer.ts — Camada de decisão que orquestra tudo.
 *
 * ARQUITETURA:
 *
 *   WhatsApp → Webhook → decisionLayer → LLM → Resposta
 *
 * O que esta camada faz:
 * 1. Recebe a mensagem + intent + entities
 * 2. Usa o routeNotes para determinar QUAIS notas buscar
 * 3. Busca as notas do knowledge_base (Supabase)
 * 4. Pré-calcula valores (calculadora FORA da LLM)
 * 5. Monta um contexto PEQUENO e FOCADO para a LLM
 * 6. A LLM só faz: conversar + apresentar + conduzir
 *
 * Obsidian = memória e regras
 * LLM = raciocínio + conversa + condução
 * Automação = motor operacional (cálculos, validações)
 */

import type { SupabaseClient } from "https://esm.sh/@supabase/supabase-js@2";
import { routeNotes, type Intent, type Entities } from "./routeNotes.ts";
import {
  calcularBolo,
  calcularBoloMeioAMeio,
  calcularSalgados,
  calcularFatias,
  dividirBoloGrande,
  calcularEntrada,
  verificarHorarioFuncionamento,
  verificarHorarioDelivery,
  validarQuantidadeSalgados,
  type RecipeInfo,
} from "./calculator.ts";

// ── Tipos ──

export interface DecisionContext {
  /** Notas do knowledge_base relevantes (conteúdo markdown) */
  notasRelevantes: string;
  /** Cálculos pré-feitos (se houver) */
  calculosTexto: string;
  /** Alertas e validações (se houver) */
  alertas: string[];
  /** Dados de pagamento do CRM */
  paymentInfo: string;
  /** Instruções custom do proprietário */
  customInstructions: string;
  /** Cardápio dinâmico (do banco de recipes) */
  cardapioDetalhado: string;
  /** Zonas de delivery com disponibilidade */
  deliveryZonesTexto: string;
  /** Promoções ativas */
  promoSummary: string;
  /** Dados do açaí */
  cardapioAcai: string;
  /** Nomes exatos dos produtos (para registro) */
  cardapioNomes: string;
  /** Nome do contato */
  contactName: string;
  /** Intent detectada */
  intent: Intent;
}

// ── Detector de entidades ──

/**
 * Detecta entidades na mensagem do cliente.
 * Complementa o intent com informações específicas.
 */
export function detectEntities(message: string): Entities {
  const msg = message.toLowerCase();

  return {
    mentionsCake: /\b(bolo|bolos)\b/i.test(msg),
    mentionsSlice: /\b(fatia|fatias|peda[cç]o)\b/i.test(msg),
    mentionsMiniSavory: /\b(mini\s*salgad|mini\s*coxinha|mini\s*kibe|mini\s*quibe|mini\s*risoles)\b/i.test(msg),
    mentionsSavory: /\b(salgad[oa]s?|coxinha|kibe|quibe|risoles|empada|pastel|bolinha)\b/i.test(msg) && !/\bmini\b/i.test(msg),
    mentionsSweets: /\b(doce|doces|docinhos?|brigadeiro|beijinho|cajuzinho|olho.de.sogra)\b/i.test(msg),
    mentionsDrink: /\b(suco|bebida|refrigerante|[aá]gua mineral|ch[aá] gelado)\b/i.test(msg) || (/\b(caf[eé])\b/i.test(msg) && !/caf[eé]\s*caf[eé]/i.test(msg)),
    mentionsDelivery: /\b(delivery|entrega|entreg[ao]|manda|enviar?|levar?)\b/i.test(msg),
    mentionsPickup: /\b(retir[ao]|buscar|busc[ao]|retirar|pegar|loja)\b/i.test(msg),
    mentionsPayment: /\b(pix|pagamento|pagar|comprovante|transferi|cart[aã]o|dinheiro)\b/i.test(msg),
    mentionsNeighborhood: extractNeighborhood(msg),
    mentionsCustomCake: /\b(personaliz|papel.de.arroz|foto.no.bolo|bolo.fake)\b/i.test(msg),
  };
}

/**
 * Tenta extrair o nome do bairro da mensagem.
 */
function extractNeighborhood(msg: string): string | null {
  // Padrões comuns: "moro no Centro", "entrega no Jaguaré", "bairro Vila Yara"
  const patterns = [
    /(?:moro|fico|sou)\s+(?:no|na|do|da|em)\s+([A-ZÀ-Ú][\w\sÀ-ú]+)/i,
    /(?:entrega|delivery)\s+(?:no|na|pra|para|pro|em)\s+([A-ZÀ-Ú][\w\sÀ-ú]+)/i,
    /bairro\s+([A-ZÀ-Ú][\w\sÀ-ú]+)/i,
  ];

  for (const pattern of patterns) {
    const match = msg.match(pattern);
    if (match && match[1]) {
      return match[1].trim();
    }
  }
  return null;
}

// ── Busca de notas ──

interface KBRow {
  caminho: string;
  titulo: string;
  conteudo: string;
}

/**
 * Busca notas do knowledge_base por caminhos.
 */
async function fetchNotas(
  supabase: SupabaseClient,
  caminhos: string[]
): Promise<KBRow[]> {
  if (caminhos.length === 0) return [];

  const { data, error } = await supabase
    .from("knowledge_base")
    .select("caminho, titulo, conteudo")
    .in("caminho", caminhos)
    .eq("ativa", true);

  if (error) {
    console.error("fetchNotas error:", error.message);
    return [];
  }

  return (data || []) as KBRow[];
}

// ── Pré-cálculo ──

interface PreCalcResult {
  texto: string;
  alertas: string[];
}

/**
 * Pré-calcula valores da mensagem. A LLM NÃO faz contas — recebe valores prontos.
 */
function preCalcular(
  message: string,
  intent: Intent,
  entities: Entities,
  recipes: RecipeInfo[]
): PreCalcResult {
  const calculos: string[] = [];
  const alertas: string[] = [];

  // Só calcular se faz sentido
  const deveCalcular = [
    "cakes", "cake_slice", "mini_savories", "savories", "sweets",
    "drinks", "pricing", "order_now", "pre_order", "delivery", "delivery_fee"
  ].includes(intent);

  if (!deveCalcular && !entities.mentionsCake && !entities.mentionsMiniSavory && !entities.mentionsSlice) {
    return { texto: "", alertas };
  }

  const msgLower = message.toLowerCase();

  // ── Detectar bolo meio a meio ──
  const meioAMeioMatch = msgLower.match(
    /meio\s*a\s*meio.*?([\w\sà-ú]+?)\s+(?:e|com)\s+([\w\sà-ú]+?)(?:\s+(?:de\s+)?(\d+)\s*kg)/i
  ) || msgLower.match(
    /(?:bolo\s+(?:de\s+)?)([\w\sà-ú]+?)\s+(?:e|com)\s+([\w\sà-ú]+?)(?:\s+(?:de\s+)?(\d+)\s*kg).*?meio\s*a\s*meio/i
  );
  if (meioAMeioMatch) {
    const sabor1 = meioAMeioMatch[1].trim();
    const sabor2 = meioAMeioMatch[2].trim();
    const peso = parseInt(meioAMeioMatch[3]);
    const resultado = calcularBoloMeioAMeio(sabor1, sabor2, peso, recipes);
    if (resultado) {
      calculos.push(
        `[CÁLCULO MEIO A MEIO] Bolo ${sabor1} + ${sabor2} (${peso}kg): usa o MAIOR preço = R$${resultado.precoKg}/kg × ${peso}kg = R$${resultado.valor.toFixed(2)} (sabor mais caro: ${resultado.saborMaisCaro})`
      );
      const entrada = calcularEntrada(resultado.valor);
      if (entrada.precisaEntrada) {
        calculos.push(
          `[CÁLCULO] Total > R$300 → entrada 50%: R$${entrada.valorEntrada.toFixed(2)}`
        );
      }
    }
  }

  // ── Detectar bolo com peso ──
  const boloMatch = !meioAMeioMatch ? msgLower.match(
    /(?:bolo\s+(?:de\s+)?)([\w\sà-ú]+?)(?:\s+(?:de\s+)?(\d+)\s*kg)/i
  ) : null;
  if (boloMatch) {
    const sabor = boloMatch[1].trim();
    const peso = parseInt(boloMatch[2]);

    if (peso > 4) {
      const formas = dividirBoloGrande(peso);
      calculos.push(
        `[CÁLCULO] Bolo de ${peso}kg → dividir em ${formas.length} formas: ${formas.map((f) => `${f}kg`).join(" + ")}`
      );
    }

    const resultado = calcularBolo(sabor, peso, recipes);
    if (resultado) {
      calculos.push(
        `[CÁLCULO] Bolo ${sabor} ${peso}kg: R$${resultado.precoKg}/kg × ${peso}kg = R$${resultado.valor.toFixed(2)}`
      );
      const entrada = calcularEntrada(resultado.valor);
      if (entrada.precisaEntrada) {
        calculos.push(
          `[CÁLCULO] Total > R$300 → entrada 50%: R$${entrada.valorEntrada.toFixed(2)}`
        );
      }
    }
  }

  // ── Detectar bolo sem peso (só sabor) ──
  if (!boloMatch && entities.mentionsCake) {
    const saborMatch = msgLower.match(/bolo\s+(?:de\s+)?([\w\sà-ú]+)/i);
    if (saborMatch) {
      const sabor = saborMatch[1].trim();
      const precoKg = recipes.find(
        (r) => r.name.toLowerCase().includes(sabor)
      );
      if (precoKg && precoKg.sale_price) {
        calculos.push(
          `[REFERÊNCIA] Bolo ${sabor}: R$${Number(precoKg.sale_price).toFixed(2)}/kg (1kg=R$${Number(precoKg.sale_price).toFixed(2)}, 2kg=R$${(Number(precoKg.sale_price) * 2).toFixed(2)}, 3kg=R$${(Number(precoKg.sale_price) * 3).toFixed(2)}, 4kg=R$${(Number(precoKg.sale_price) * 4).toFixed(2)})`
        );
      }
    }
  }

  // ── Detectar salgados ──
  const salgadosMatch = msgLower.match(
    /(\d+)\s*(?:unidades?\s+(?:de\s+)?)?(?:mini\s+)?(?:salgad|coxinha|kibe|quibe|risoles)/i
  );
  if (salgadosMatch) {
    const qtd = parseInt(salgadosMatch[1]);
    const validacao = validarQuantidadeSalgados(qtd);
    if (!validacao.valido) {
      alertas.push(
        `[SALGADOS] Quantidade ${qtd} não é múltiplo de 25. Sugestões: ${validacao.sugestaoInferior} ou ${validacao.sugestaoSuperior}`
      );
    }
    const resultado = calcularSalgados(qtd);
    calculos.push(
      `[CÁLCULO] ${qtd} mini salgados: R$${resultado.valor.toFixed(2)} (R$175/cento)`
    );
  }

  // ── Detectar fatias ──
  const fatiaMatch = msgLower.match(/(\d+)\s*fatias?/i);
  if (fatiaMatch) {
    const qtd = parseInt(fatiaMatch[1]);
    const resultado = calcularFatias(qtd);
    calculos.push(
      `[CÁLCULO] ${qtd} fatia(s): ${qtd} × R$25 = R$${resultado.valor.toFixed(2)}`
    );
  }

  // ── Verificar horário ──
  const horario = verificarHorarioFuncionamento();
  if (!horario.aberto) {
    alertas.push(`[HORÁRIO] ${horario.mensagem}`);
  }

  // ── Verificar delivery ──
  if (entities.mentionsDelivery || intent === "delivery" || intent === "delivery_fee") {
    const deliveryHorario = verificarHorarioDelivery();
    if (!deliveryHorario.disponivel) {
      alertas.push(`[DELIVERY] ${deliveryHorario.mensagem}`);
    }
  }

  // ── Detectar decoração ──
  if (/\b(decorac[aã]o|decorar|decorado|personaliz|chantininho|topo|pasta\s*americana)\b/i.test(msgLower)) {
    calculos.push(`[CÁLCULO] Decoração/personalização: +R$30,00 (somar ao total)`);
  }

  // ── Bairro mencionado ──
  if (entities.mentionsNeighborhood) {
    calculos.push(
      `[INFO] Cliente mencionou bairro: ${entities.mentionsNeighborhood} → buscar taxa na tabela`
    );
  }

  return {
    texto: calculos.length > 0 ? calculos.join("\n") : "",
    alertas,
  };
}

// ── Montagem do contexto final ──

/**
 * Executa toda a camada de decisão e retorna o contexto
 * pronto para ser injetado no prompt da LLM.
 */
export async function buildDecisionContext(
  supabase: SupabaseClient,
  message: string,
  intent: Intent,
  entities: Entities,
  contactName: string,
  paymentInfo: string,
  customInstructions: string,
  promoSummary: string,
  cardapioAcai: string,
  cardapioDetalhado: string,
  cardapioNomes: string,
  deliveryZonesTexto: string,
  recipes: RecipeInfo[]
): Promise<DecisionContext> {
  // 1. Rotear: quais notas buscar?
  const caminhos = routeNotes(intent, entities);

  // 2. Buscar notas do knowledge_base
  const notas = await fetchNotas(supabase, caminhos);
  const notasRelevantes = notas
    .map((n) => `═══ ${n.titulo.toUpperCase()} ═══\n${n.conteudo}`)
    .join("\n\n");

  // 3. Pré-calcular valores (FORA da LLM)
  const preCalc = preCalcular(message, intent, entities, recipes);

  return {
    notasRelevantes,
    calculosTexto: preCalc.texto,
    alertas: preCalc.alertas,
    paymentInfo,
    customInstructions,
    cardapioDetalhado,
    deliveryZonesTexto,
    promoSummary,
    cardapioAcai,
    cardapioNomes,
    contactName,
    intent,
  };
}

/**
 * Monta o system prompt final.
 *
 * PROMPT ENXUTO:
 * - Identidade mínima (6 linhas)
 * - Notas relevantes do knowledge_base (só as necessárias)
 * - Cálculos pré-feitos (exatos)
 * - Cardápio (fonte de verdade)
 * - Dados do cliente
 * - Lembrete final
 */
export function buildSmartPrompt(ctx: DecisionContext): string {
  const parts: string[] = [];

  // 1. Prompt fixo MÍNIMO — identidade e papel apenas
  //    Todo conhecimento de atendimento vem do vault (notas do knowledge_base)
  parts.push(`Você é a atendente virtual da Café Café Confeitaria, Osasco-SP.
Atende clientes pelo WhatsApp de forma humana, acolhedora e profissional.

Seu papel: conversar naturalmente, tirar dúvidas, ajudar na escolha e registrar pedidos.
- Use SOMENTE as informações do contexto abaixo para responder.
- Nunca invente preço, taxa, produto, prazo ou disponibilidade.
- Se faltar informação, diga que vai verificar com a equipe.
- Use os CÁLCULOS PRÉ-FEITOS quando disponíveis — são exatos.
- Respostas curtas e naturais (estilo WhatsApp).`);

  // 2. Notas relevantes do knowledge_base (Obsidian)
  if (ctx.notasRelevantes) {
    parts.push(`\n${ctx.notasRelevantes}`);
  }

  // 3. Cálculos pré-feitos (A LLM DEVE usar estes valores)
  if (ctx.calculosTexto) {
    parts.push(`\n═══ CÁLCULOS PRÉ-FEITOS (USE ESTES VALORES — SÃO EXATOS) ═══\n${ctx.calculosTexto}`);
  }

  // 4. Alertas
  if (ctx.alertas.length > 0) {
    parts.push(`\n═══ ALERTAS ═══\n${ctx.alertas.join("\n")}`);
  }

  // 5. Instruções do proprietário
  if (ctx.customInstructions) {
    parts.push(`\n═══ INSTRUÇÕES DO PROPRIETÁRIO (PRIORIDADE MÁXIMA) ═══\n${ctx.customInstructions}`);
  }

  // 6. Açaí (quando relevante)
  const needsAcai = ["cakes", "cake_slice", "pricing", "order_now", "pre_order", "drinks"].includes(ctx.intent);
  if (ctx.cardapioAcai && needsAcai) {
    parts.push(`\n═══ AÇAÍ ═══\n${ctx.cardapioAcai}`);
  }

  // 7. Cardápio detalhado (fonte de verdade)
  const needsMenu = ["cakes", "cake_slice", "mini_savories", "savories", "sweets", "drinks", "pricing", "order_now", "pre_order"].includes(ctx.intent);
  if (ctx.cardapioDetalhado && needsMenu) {
    parts.push(`\n═══ CARDÁPIO E PREÇOS (FONTE DE VERDADE) ═══\n${ctx.cardapioDetalhado}\n⚠️ Se NÃO está aqui, NÃO EXISTE.`);
  }

  // 8. Zonas de delivery
  const needsDelivery = ["delivery", "delivery_fee", "order_now", "pre_order"].includes(ctx.intent);
  if (ctx.deliveryZonesTexto && needsDelivery) {
    parts.push(`\n═══ TAXAS DE ENTREGA ═══\n${ctx.deliveryZonesTexto}`);
  }

  // 9. Dados do cliente
  parts.push(`\n═══ DADOS DO CLIENTE ═══
Nome: ${ctx.contactName || "não informado"}
Promoções: ${ctx.promoSummary || "nenhuma"}
Pagamento: ${ctx.paymentInfo}
Cardápio PDF: http://bit.ly/3OYW9Fw`);

  // 10. Nomes para registro (quando relevante)
  if (ctx.cardapioNomes && ["order_now", "pre_order", "payment"].includes(ctx.intent)) {
    parts.push(`\n⚠️ Nomes exatos para registro: ${ctx.cardapioNomes}`);
  }

  // 11. Lembrete final
  parts.push(`\n═══ ANTES DE RESPONDER ═══
1. Li TODA a mensagem? 2. Verifiquei HISTÓRICO? 3. Usei CÁLCULOS PRÉ-FEITOS?
4. Produto EXISTE no cardápio? 5. Resposta CURTA e NATURAL?
RESPONDA SOMENTE COM A MENSAGEM PARA O CLIENTE.`);

  return parts.join("\n");
}

