  },
];

/**
 * Determina quais notas buscar no knowledge_base.
 *
 * Combina:
 * 1. Notas SEMPRE carregadas (personalidade)
 * 2. Notas por intent
 * 3. Notas extras por stage
 * 4. Notas por palavras-chave na mensagem
 * 5. Se tem pedido em andamento: notas de continuidade
 *
 * Retorna caminhos ÚNICOS (sem duplicatas).
 */
export function routeToNotes(
  intent: PromptIntent,
  stage: PromptStage,
  message: string,
  hasOrderInProgress: boolean
): string[] {
  const paths = new Set<string>(NOTAS_SEMPRE);

  // 1. Notas por intent
  const intentPaths = INTENT_ROUTES[intent] || [];
  intentPaths.forEach((p) => paths.add(p));

  // 2. Notas extras por stage
  const stagePaths = STAGE_EXTRAS[stage] || [];
  stagePaths.forEach((p) => paths.add(p));

  // 3. Notas por palavras-chave na mensagem
  for (const route of KEYWORD_ROUTES) {
    if (route.keywords.test(message)) {
      route.paths.forEach((p) => paths.add(p));
    }
  }

  // 4. Se tem pedido em andamento
  if (hasOrderInProgress) {
    paths.add("sistema/validacao-pedido");
    paths.add("sistema/calculo-pedido");
  }

  return Array.from(paths);
}

/**
 * fetchRules.ts — Busca regras do banco agent_rules baseado no intent/stage.
 *
 * Em vez de carregar TODAS as regras no prompt (causando "esquecimento" do LLM),
 * busca apenas as regras relevantes para o contexto atual da conversa.
 *
 * Regras com `sempre_ativa = true` são SEMPRE incluídas.
 * Regras com intents/stages específicos só são incluídas quando batem com o contexto.
 */

import type { SupabaseClient } from "https://esm.sh/@supabase/supabase-js@2";
import type { PromptIntent, PromptStage } from "./atendentePromptModules.ts";

export interface AgentRule {
  id: number;
  categoria: string;
  titulo: string;
  conteudo: string;
  prioridade: string;
  intents: string[];
  stages: string[];
  sempre_ativa: boolean;
  ordem: number;
}

/** Prioridade para ordenação */
const PRIORIDADE_PESO: Record<string, number> = {
  critica: 0,
  alta: 1,
  media: 2,
  baixa: 3,
};

/**
 * Busca regras relevantes do banco `agent_rules`.
 *
 * Lógica:
 * 1. Regras com `sempre_ativa = true` → SEMPRE incluídas
 * 2. Regras cujo array `intents` contém o intent atual → incluídas
 * 3. Regras cujo array `stages` contém o stage atual → incluídas
 * 4. Regras com intents e stages vazios que NÃO são sempre_ativa → NÃO incluídas
 *    (evita carregar tudo)
 *
 * Ordena por: prioridade (critica primeiro) → ordem → id
 */
export async function fetchRelevantRules(
  supabase: SupabaseClient,
  intent: PromptIntent,
  stage: PromptStage,
  hasOrderInProgress: boolean
): Promise<AgentRule[]> {
  // Buscar todas as regras ativas do banco (são poucas, ~15-20 linhas)
  const { data: allRules, error } = await supabase
    .from("agent_rules")
    .select("id, categoria, titulo, conteudo, prioridade, intents, stages, sempre_ativa, ordem")
    .eq("ativa", true)
    .order("ordem", { ascending: true });

  if (error) {
    console.error("fetchRelevantRules error:", error.message);
    return [];
  }

  const rules = (allRules || []) as AgentRule[];

  // Filtrar regras relevantes
  const relevant = rules.filter((rule) => {
    // Sempre ativa → sempre incluída
    if (rule.sempre_ativa) return true;

    // Verificar match por intent
    const matchIntent =
      rule.intents.length === 0 || rule.intents.includes(intent);

    // Verificar match por stage
    const matchStage =
      rule.stages.length === 0 || rule.stages.includes(stage);

    // Se ambos intents e stages são vazios e NÃO é sempre_ativa → não incluir
    // (isso evita que regras "órfãs" sejam carregadas em todo contexto)
    if (rule.intents.length === 0 && rule.stages.length === 0) {
      return false; // já tratado por sempre_ativa acima
    }

    // Incluir se bate com intent OU stage
    return matchIntent || matchStage;
  });

  // Se tem pedido em andamento, garantir que continuidade está presente
  if (hasOrderInProgress) {
    const hasContinuidade = relevant.some(
      (r) => r.categoria === "continuidade"
    );
    if (!hasContinuidade) {
      const continuidadeRule = rules.find(
        (r) => r.categoria === "continuidade"
      );
      if (continuidadeRule) relevant.push(continuidadeRule);
    }
  }

  // Ordenar: prioridade (critica primeiro) → ordem → id
  relevant.sort((a, b) => {
    const pa = PRIORIDADE_PESO[a.prioridade] ?? 2;
    const pb = PRIORIDADE_PESO[b.prioridade] ?? 2;
    if (pa !== pb) return pa - pb;
    if (a.ordem !== b.ordem) return a.ordem - b.ordem;
    return a.id - b.id;
  });

  return relevant;
}

/**
 * Monta o bloco de regras para o system prompt.
 * Cada regra vira uma seção com título e conteúdo.
 */
export function buildRulesBlock(rules: AgentRule[]): string {
  if (rules.length === 0) return "";

  return rules
    .map((r) => {
      const prioLabel =
        r.prioridade === "critica"
          ? "⚠️ PRIORIDADE CRÍTICA"
          : r.prioridade === "alta"
          ? "🔴 PRIORIDADE ALTA"
          : "";
      const header = prioLabel
        ? `═══ ${r.titulo.toUpperCase()} ${prioLabel} ═══`
        : `═══ ${r.titulo.toUpperCase()} ═══`;
      return `${header}\n${r.conteudo}`;
    })
    .join("\n\n");
}

/**
 * Versão completa: busca regras + monta o bloco de texto.
 */
export async function fetchAndBuildRules(
  supabase: SupabaseClient,
  intent: PromptIntent,
  stage: PromptStage,
  hasOrderInProgress: boolean
): Promise<string> {
  const rules = await fetchRelevantRules(
    supabase,
    intent,
    stage,
    hasOrderInProgress
  );
  return buildRulesBlock(rules);
}

import type { SupabaseClient } from "https://esm.sh/@supabase/supabase-js@2";

export interface OwnerInfo {
  ownerUserId: string;
  ownerPhone: string | null;
}

/**
 * Obtém user_id e telefone do dono (único registro em user_roles com role = 'owner').
 * Usa service role. Retorna null se não houver dono.
 */
export async function getOwner(supabase: SupabaseClient): Promise<OwnerInfo | null> {
  const { data: roleRow } = await supabase
    .from("user_roles")
    .select("user_id")
    .eq("role", "owner")
    .limit(1)
    .maybeSingle();
  if (!roleRow?.user_id) return null;
  const { data: profile } = await supabase
    .from("profiles")
    .select("user_id, phone")
    .eq("user_id", roleRow.user_id)
    .maybeSingle();
  if (!profile) return { ownerUserId: roleRow.user_id, ownerPhone: null };
  return { ownerUserId: profile.user_id, ownerPhone: profile.phone ?? null };
}

/** Normaliza número (apenas dígitos, últimos 11). O + é opcional ao digitar. */
export function normalizePhone(phone: string): string {
  return phone.replace(/\D/g, "").slice(-11) || phone;
}

/**
 * Parseia string com vários números (vírgula ou quebra de linha; + opcional).
 * Retorna array de números normalizados (apenas os com >= 10 dígitos).
 */
export function parseOwnerPhonesList(value: string | null | undefined): string[] {
  if (!value || typeof value !== "string") return [];
  const parts = value.split(/[\n,;]+/).map((s) => normalizePhone(s.trim()));
  return [...new Set(parts)].filter((p) => p.length >= 10);
}

/** Verifica se o número do remetente está na lista de donos. */
export function isOwnerPhoneInList(remotePhone: string, ownerPhonesList: string[]): boolean {
  if (ownerPhonesList.length === 0) return false;
  const normalized = normalizePhone(remotePhone);
  if (normalized.length < 10) return false;
  return ownerPhonesList.some((owner) => normalizePhone(owner) === normalized);
}

/** Verifica se o número do remetente é o do dono (perfil ou override em crm_settings). Mantido para compat. */
export function isOwnerPhone(
  remotePhone: string,
  ownerPhone: string | null,
  settingsOverride: string | null
): boolean {
  const list: string[] = [];
  if (settingsOverride?.trim()) list.push(settingsOverride.trim());
  if (ownerPhone?.trim()) list.push(ownerPhone.trim());
  return isOwnerPhoneInList(remotePhone, list);
}

/**
 * orderValidator.ts — Validador de fechamento de pedido.
 *
 * Verifica se todos os campos necessários estão preenchidos
 * antes de permitir o registro na plataforma.
 *
 * Retorna uma lista de campos faltantes para que a LLM
 * saiba o que perguntar ao cliente.
 */

export interface DadosPedido {
  customerName?: string | null;
  customerPhone?: string | null;
  items?: { name: string; quantity: number; weight?: number }[];
  modalidade?: "delivery" | "encomenda" | "retirada" | null;
  endereco?: string | null;
  bairro?: string | null;
  dataEntrega?: string | null;
  horarioEntrega?: string | null;
  formaPagamento?: string | null;
  totalCalculado?: number | null;
  clienteConfirmou?: boolean;
}

export interface ValidacaoResult {
  valido: boolean;
  camposFaltantes: string[];
  proximaPergunta: string | null;
}

/**
 * Valida se o pedido tem todos os campos necessários.
 * Retorna os campos faltantes em ordem de prioridade.
 */
export function validarPedido(dados: DadosPedido): ValidacaoResult {
  const faltantes: string[] = [];

  // 1. Itens (obrigatório sempre)
  if (!dados.items || dados.items.length === 0) {
    faltantes.push("itens");
  }

  // 2. Modalidade (obrigatório sempre)
  if (!dados.modalidade) {
    faltantes.push("modalidade");
  }

  // 3. Nome (obrigatório)
  if (!dados.customerName) {
    faltantes.push("nome");
  }

  // 4. Se delivery: endereço e bairro
  if (dados.modalidade === "delivery") {
    if (!dados.endereco) faltantes.push("endereco");
    if (!dados.bairro) faltantes.push("bairro");
  }

  // 5. Se encomenda: data e horário
  if (dados.modalidade === "encomenda") {
    if (!dados.dataEntrega) faltantes.push("data_entrega");
    if (!dados.horarioEntrega) faltantes.push("horario_entrega");
    // Se vai entregar (não retirar), precisa endereço também
    // Isso é tratado pelo fluxo na conversa
  }

  // 6. Se retirada: horário
  if (dados.modalidade === "retirada") {
    if (!dados.horarioEntrega) faltantes.push("horario_retirada");
  }

  // 7. Total calculado
  if (dados.totalCalculado == null || dados.totalCalculado <= 0) {
    faltantes.push("total");
  }

  // 8. Pagamento
  if (!dados.formaPagamento) {
    faltantes.push("pagamento");
  }

  // 9. Confirmação do cliente
  if (!dados.clienteConfirmou) {
    faltantes.push("confirmacao");
  }

  // Gerar próxima pergunta baseada no primeiro campo faltante
  const proximaPergunta = faltantes.length > 0
    ? gerarPergunta(faltantes[0], dados)
    : null;

  return {
    valido: faltantes.length === 0,
    camposFaltantes: faltantes,
    proximaPergunta,
  };
}

/**
 * Gera a sugestão de próxima pergunta para a LLM.
 */
function gerarPergunta(campo: string, dados: DadosPedido): string {
  switch (campo) {
    case "itens":
      return "O que você gostaria de pedir?";
    case "modalidade":
      return "É retirada, delivery ou encomenda?";
    case "nome":
      return "Qual seu nome pra eu anotar?";
    case "endereco":
      return "Qual seu endereço completo pra entrega?";
    case "bairro":
      return "Qual seu bairro pra eu calcular a taxa?";
    case "data_entrega":
      return "Pra qual data você precisa?";
    case "horario_entrega":
      return "Qual horário de entrega fica bom?";
    case "horario_retirada":
      return "Qual horário quer retirar na loja?";
    case "total":
      return "[SISTEMA] Calcular total do pedido.";
    case "pagamento":
      return "Vai ser PIX, cartão ou dinheiro?";
    case "confirmacao": {
      const total = dados.totalCalculado ?? 0;
      return `O total ficou R$${total.toFixed(2)}. Tudo certo pra confirmar?`;
    }
    default:
      return "Falta alguma informação. O que mais posso anotar?";
  }
}

/**
 * Verifica se um produto existe no cardápio.
 */
export function produtoExiste(
  nomeProduto: string,
  recipes: { name: string }[]
): boolean {
  const normalizado = nomeProduto.toLowerCase().trim();
  return recipes.some((r) => r.name.toLowerCase().trim() === normalizado);
}

/**
 * Encontra o produto mais parecido (fuzzy match simples).
 * Útil quando o cliente escreve "ninho morango" em vez de "Ninho com Morango".
 */
export function buscarProdutoSimilar(
  busca: string,
  recipes: { name: string }[]
): string | null {
  const normalizado = busca.toLowerCase().trim();
  const palavras = normalizado.split(/\s+/);

  // Match exato
  const exato = recipes.find(
    (r) => r.name.toLowerCase().trim() === normalizado
  );
  if (exato) return exato.name;

  // Match parcial: todas as palavras-chave presentes
  const parcial = recipes.find((r) => {
    const nome = r.name.toLowerCase();
    return palavras.every((p) => nome.includes(p));
  });
  if (parcial) return parcial.name;

  // Match por maior sobreposição de palavras
  let melhorMatch: { name: string; score: number } | null = null;
  for (const recipe of recipes) {
    const nomeRecipe = recipe.name.toLowerCase();
    const score = palavras.filter((p) => nomeRecipe.includes(p)).length;
    if (score > 0 && (!melhorMatch || score > melhorMatch.score)) {
      melhorMatch = { name: recipe.name, score };
    }
  }

  return melhorMatch && melhorMatch.score >= palavras.length * 0.5
    ? melhorMatch.name
    : null;
}

/**
 * Módulo de segurança: sanitização, validação e proteção contra abusos.
 * Uso em webhooks e agent-chat.
 */

/** Tamanho máximo da mensagem do usuário (caracteres). */
export const MAX_MESSAGE_LENGTH = 4096;

/** Tamanho máximo do texto extraído de PDF anexado (caracteres). */
export const MAX_PDF_EXTRACTED_TEXT_LENGTH = 12000;

/** Tamanho máximo do nome/contato. */
export const MAX_NAME_LENGTH = 200;

/** Número máximo de mensagens no histórico enviado ao LLM. */
export const MAX_HISTORY_MESSAGES = 12;

/** Telefone: só dígitos, máx 15 (E.164). */
export const PHONE_MAX_DIGITS = 15;

/**
 * Sanitiza mensagem: trim, limite de tamanho, remove null bytes.
 */
export function sanitizeMessage(input: unknown): string {
  if (input == null) return "";
  const s = String(input).replace(/\0/g, "").trim();
  return s.slice(0, MAX_MESSAGE_LENGTH);
}

/**
 * Sanitiza nome/contato para exibição e contexto.
 */
export function sanitizeName(input: unknown): string {
  if (input == null) return "";
  const s = String(input).replace(/\0/g, "").trim();
  return s.slice(0, MAX_NAME_LENGTH);
}

/**
 * Normaliza e valida telefone: apenas dígitos, até PHONE_MAX_DIGITS.
 * Retorna string vazia se inválido.
 */
export function sanitizePhone(input: unknown): string {
  if (input == null) return "";
  const digits = String(input).replace(/\D/g, "");
  const normalized = digits.slice(-PHONE_MAX_DIGITS);
  return normalized.length >= 10 ? normalized : "";
}

/**
 * Valida URL da Evolution para evitar SSRF (apenas HTTPS, sem localhost/IP privado).
 */
export function isAllowedEvolutionBaseUrl(url: string): boolean {
  const u = url.trim().replace(/\/$/, "");
  if (!u.startsWith("https://")) return false;
  try {
    const parsed = new URL(u);
    const host = parsed.hostname.toLowerCase();
    if (host === "localhost" || host === "127.0.0.1" || host.startsWith("192.168.") || host.startsWith("10.") || host.endsWith(".local")) return false;
    if (parsed.protocol !== "https:") return false;
    return true;
  } catch {
    return false;
  }
}

/**
 * Verifica segredo do webhook (header ou query) para aceitar apenas chamadas da Evolution.
 * Se configuredSecret for vazio ou parecer texto de placeholder, não exige verificação.
 */
export function verifyWebhookSecret(
  configuredSecret: string | null | undefined,
  requestHeader: string | null,
  requestQuery: string | null
): boolean {
  let secret = (configuredSecret ?? "").trim();
  if (secret.length > 60 || /header|evolution|opcional|na evolution/i.test(secret)) secret = "";
  if (!secret) return true;
  const provided = (requestHeader || requestQuery || "").trim();
  if (!provided) return false;
  return provided === secret;
}

/**
 * Sanitiza histórico de mensagens para o LLM.
 */
export function sanitizeHistory(
  raw: unknown
): { role: "user" | "assistant"; content: string }[] {
  if (!Array.isArray(raw)) return [];
  const out: { role: "user" | "assistant"; content: string }[] = [];
  for (const m of raw) {
    if (!m || typeof m !== "object") continue;
    const role = (m as { role?: string }).role;
    if (role !== "user" && role !== "assistant") continue;
    const content = sanitizeMessage((m as { content?: unknown }).content);
    if (content) out.push({ role, content });
    if (out.length >= MAX_HISTORY_MESSAGES) break;
  }
  return out;
}

import type { SupabaseClient } from "https://esm.sh/@supabase/supabase-js@2";

/**
 * Envia o pedido/encomenda para a função edge `receive-orders`,
 * no formato exato que você passou (customer, items, paymentMethod, etc.).
 */
export async function sendTicketFlowOrder(
  supabase: SupabaseClient,
  phone: string,
  params: {
    type: "pedido" | "encomenda";
    external_id?: string | null;
    channel: string;
    total: number;
    payment_method: string;
    items: { name: string; quantity: number; unit_price: number; category?: string | null; unit?: string | null }[];
    deliveryDate?: string | null;
    deliveryTime?: string | null;
  }
): Promise<void> {
  const endpoint = "https://dlugexjpftqwkfawlnov.supabase.co/functions/v1/receive-orders";
  const normalizedPhone = phone.replace(/\D/g, "");

  // Busca dados do cliente no Supabase para preencher endereço
  let customerDb: { name?: string; phone?: string; address?: string | null } | null = null;
  try {
    const { data } = await supabase
      .from("customers")
      .select("name, phone, address")
      .eq("phone", normalizedPhone)
      .maybeSingle();
    customerDb = (data as any) ?? null;
  } catch {
    customerDb = null;
  }

  const customerName = customerDb?.name || "Cliente WhatsApp";
  const customerPhone = customerDb?.phone || normalizedPhone;
  const fullAddress = (customerDb?.address || "").trim();

  // Tentativa simples de quebrar endereço em rua/número/bairro/cidade
  let street = "";
  let number = "";
  let neighborhood = "";
  let city = "Osasco";
  if (fullAddress) {
    const parts = fullAddress.split(",").map((p) => p.trim());
    street = parts[0] || "";
    if (parts[1]) number = parts[1];
    if (parts[2]) neighborhood = parts[2];
    if (parts[3]) city = parts[3];
  }

  const deliveryType = params.channel === "retirada" ? "pickup" : "delivery";

  const body = {
    customer: {
      name: customerName,
      phone: customerPhone,
      street,
      number,
      neighborhood,
      city,
    },
    items: params.items.map((it) => ({
      productName: it.name,
      quantity: it.quantity,
      unitPrice: it.unit_price,
      category: it.category || "OTHER",
      unit: it.unit || "UN",
    })),
    paymentMethod: params.payment_method || "cash",
    deliveryDate: params.deliveryDate || undefined,
    deliveryTime: params.deliveryTime || undefined,
    deliveryType,
    productionDate: params.deliveryDate || undefined,
    productionTime: params.deliveryTime || undefined,
    attendant: "IA WhatsApp",
  };

  // Sync customer to external platform
  const syncCustomersUrl = "https://dlugexjpftqwkfawlnov.supabase.co/functions/v1/sync-customers";
  try {
    await fetch(syncCustomersUrl, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify([{
        name: customerName,
        phone: customerPhone,
        street,
        number,
        neighborhood,
        city,
      }]),
    });
  } catch (e) {
    console.error("sync-customers exception", (e as Error).message);
  }

  // Send order to external platform
  try {
    const res = await fetch(endpoint, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(body),
    });
    if (!res.ok) {
      const txt = await res.text().catch(() => "");
      console.error("ticketflow receive-orders error", res.status, txt.slice(0, 300));
    }
  } catch (e) {
    console.error("ticketflow receive-orders exception", (e as Error).message);
  }
}

/**
 * Extração de texto de PDF para uso pelo assistente e atendente.
 * Funciona em Deno (Supabase Edge). Usa unpdf (PDF.js serverless).
 */

const MAX_PDF_BYTES = 5 * 1024 * 1024; // 5 MB
const MAX_EXTRACTED_TEXT_LENGTH = 11000; // caracteres para caber no contexto do LLM

/**
 * Extrai texto de um PDF a partir dos bytes (ArrayBuffer ou Uint8Array).
 * Retorna string vazia se falhar ou se o arquivo não for PDF válido.
 */
export async function extractTextFromPdf(bytes: ArrayBuffer | Uint8Array): Promise<string> {
  const buffer = bytes instanceof Uint8Array ? bytes : new Uint8Array(bytes);
  if (buffer.length === 0 || buffer.length > MAX_PDF_BYTES) return "";

  try {
    const { extractText, getDocumentProxy } = await import("https://esm.sh/unpdf@1.4.0?target=deno");
    const pdf = await getDocumentProxy(buffer);
    const { text } = await extractText(pdf, { mergePages: true });
    const cleaned = (text || "").replace(/\s+/g, " ").trim();
    return cleaned.slice(0, MAX_EXTRACTED_TEXT_LENGTH);
  } catch (_e) {
    return "";
  }
}

/**
 * Verifica se o mimetype ou nome do arquivo indica PDF.
 */
export function isPdfMimetype(mimetype: string | undefined): boolean {
  if (!mimetype) return false;
  const m = mimetype.toLowerCase();
  return m === "application/pdf" || m.endsWith("/pdf");
}

export function isPdfFileName(fileName: string | undefined): boolean {
  if (!fileName) return false;
  return fileName.toLowerCase().endsWith(".pdf");
}
